window.__dh_data["ne"] = {
  "": "Content-Type: text/plain; charset=UTF-8\nContent-Transfer-Encoding: 8bit\n",
  "title": "धम्मपद",
  "chaps": "अध्यायहरू",
  "fontsize": "फन्ट साइज",
  "chap1": "यमकवग्गो",
  "1": "मनको धर्म हो जुनसुकै काममा पनि अगुवा हुनु, र मन मुख्य भएर जताततै पुगेको हुन्छ । त्यसकारण अशुद्ध मन लिएर कसैले बोल्यो वा गर्यो भने बयलको पछि-पछि गाडाको पाङ्ग्रा आए झैं दुःख पछि लागेर आउँछ ।",
  "2": "मनको धर्मजुनसुकै काममा पनि अगुवा हुनु, र मन मुख्य भएर जताततै पुगेको हुन्छ । त्यसकारण शुद्ध मन लिएर कसैले बोल्यो वा गर्यो भने आफ्नो पीछा नछोड्ने छायाँ आए झैं सुख पछि-पछि लागेर आउँछ ।",
  "3": "'मलाई गाली गर्यो' 'मलाई पिट्यो' 'मलाई हराइदियो' र 'मेरो लगिदियो' इत्यादि भनेर जसले आफ्नो मनमा बराबर विचार गर्छ, त्यसको मनमा कहिले पनि वैरभाव शान्त हुने छैन ।",
  "4": "'मलाई गाली गर्यो' 'मलाई पिट्यो' 'मलाई हराइदियो' र 'मेरो लगिदियो' इत्यादि भनेर जसले आफ्नो मनमा बराबर विचार गर्दैन, त्यसको मनमा वैरभाव शान्त हुन्छ ।",
  "5": "रिसले वैरभाव शान्त हुने छैन, प्रेमभावले मात्र वैरभाव शान्त हुन सक्छ, यही सनातनदेखि चलिआएको धर्म हो ।",
  "6": "मूर्खले मात्र हामीले एकदिन अवश्य मर्नुपर्छ भनी विचार गर्दैन, 'हामी मर्छौं' भनी विचार गर्ने बित्तिकै कलह शान्त हुन्छ ।",
  "7": "इन्द्रिय संयम नगरी, राम्रो देख्ने, भोजनमा मात्रा नजान्ने, वीर्यहीन हुने यस्तालाई, बतासले रुख ढाले झैं मारले बिताउँछ ।",
  "8": "इन्द्रिय संयम गरी, राम्रो नदेख्ने, भोजनमा मात्रा ज्ञान राख्ने र श्रद्धा-वीर्य कायम राखेका यस्तालाई पर्वतको ढुङ्गा बतासले हल्लाउन नसके झैं मारले डगाउन सक्दैन ।",
  "9": "इन्द्रिय दमन नगरी, सत्यज्ञानबाट दूर भई आफ्नो मनलाई स्वच्छ नराख्नेलाई गेरुवा वस्त्र सुहाउँदैन ।",
  "10": "क्लेशलाई दूरगरी, आफ्नो मन स्वच्छ राखी, शीलवान् भई, इन्द्रिय दमन गरेर सत्यज्ञानमा बस्नेलाई गेरुवा वस्त्र सुहाउँछ ।",
  "11": "असारलाई सार, सारलाई असार ठान्ने यस्तो मिथ्यादृष्टि हुने व्यक्तिलाई सार पदार्थको लाभ हुँदैन ।",
  "12": "सारलाई सार, असारलाई असार देखेर सम्यग्दृष्टि हुने यस्ता व्यक्तिलाई सार पदार्थको लाभ हुन्छ ।",
  "13": "नराम्रोसित छाएको छानाबाट पानी चुहे झैं राम्रोसँग नबाँधेको चित्तमा राग चुहिन्छ ।",
  "14": "जस्तो राम्रोसँग छाएको छानाबाट पानी चुहिँदैन, त्यस्तै शुद्ध चित्तमा राग चुहिँदैन ।",
  "15": "पापी व्यक्तिलाई इहलोक, परलोक दुवै लोकमा शोक हुन्छ, आफूले गरेको खराब कामलाई देखेर आफैँ दुःखित र पीडित हुन्छ ।",
  "16": "पुण्यवान् व्यक्ति इहलोक, परलोक दुवै लोकमा सुखी हुन्छ, आफूले गरेको राम्रो कामलाई देखेर आफैँ सुखी हुन्छ, प्रमुदित हुन्छ ।",
  "17": "पापी व्यक्तिलाई यहाँ पनि, वहाँ पनि दुवै लोकमा ताप हुन्छ, 'मैले पाप गरेँ' भन्ने विचारले मनमा सन्ताप हुन्छ, दुर्गतिमा पुगेर उसलाई झन् बढी ताप हुन्छ ।",
  "18": "पुण्यवान् व्यक्तिलाई इहलोक, परलोक दुवैमा आनन्दको अनुभव हुन्छ, 'मैले पुण्य गरेँ' भनी आनन्दित हुन्छ, परलोकमा पुगेर यहाँभन्दा पनि धेरै आनन्द प्राप्ति हुन्छ ।",
  "19": "जस्तो अर्काको गाई चराउने गोठालाले दूध प्राप्त गर्न सक्दैन, त्यस्तै धेरै धर्मको कुरा गर्न जानेर पनि तदनुसार आचरण नगर्नेलाई श्रमणत्व फल प्राप्त हुन सक्दैन ।",
  "20": "अलिकता मात्र धर्मको कुरा गर्न सक्ने भएता पनि धर्मानुसार आचरण गर्ने, राग, द्वेष र मोहलाई हटाई राम्रो धर्मावबोध भएर आफ्नो चित्तलाई क्लेशबाट हटाई, इहलोक र परलोकको चिन्ता नगर्नेलाई श्रमणत्व फल प्राप्त हुन सक्दछ ।",
  "chap2": "अप्पमादवग्गो",
  "21": "अप्रमाद निर्वाणको बाटो हो, प्रमाद मृत्युको बाटो हो, प्रमादीहरू मर्ने सरह हुन्छन्, अप्रमादीहरू मर्दैनन् ।",
  "22": "आर्यधर्ममा नियुक्त भएका पण्डितहरूले अप्रमादमा भएको जुन विशेषता हो त्यसलाई देखेर, अप्रमादी हुनुमा नै विशेष रुचि देखाउँछन् ।",
  "23": "धैर्य राख्न सक्ने ध्यानीहरूले आफ्नो वीर्यलाई ध्यानको सहाराले बढाएर, जन्म-मरण रहित निर्वाण पद र अनुत्तर योगक्षेम प्राप्त गर्दछन् ।",
  "24": "उद्योगी, स्मृतिवान् भई शुभकाम राम्रोसँग गरी, संयमी भएर धार्मिक जीवन बिताई अप्रमादी हुने व्यक्तिको यश बढ्दछ ।",
  "25": "बुद्धिमान्ले संयम र चित्त दमन गरी, अप्रमादी भएर बाढी आए पनि बगाउन नसकिने टापु (जस्तै) आफूलाई बनाउनुपर्छ ।",
  "26": "मूर्खहरू प्रमादी हुन्छन्, पण्डितहरू श्रेष्ठले धन रक्षा गरे झैं अप्रमादलाई रक्षा गर्दछन् ।",
  "27": "प्रमादी नहोऊ, कामविषयमा आसक्त नहोऊ, अप्रमादी भई ध्यान गर्यो भने विपुल सुख प्राप्त हुन्छ ।",
  "28": "जुन बखतमा पण्डितले प्रमादलाई अप्रमादले जितेर आफू शोक-तापबाट रहित हुन्छ, त्यस बखत उसले प्रज्ञारूपी उच्च प्रासादमा बसी शोकी-सन्तप्त प्राणीहरूलाई, पहाडको टुप्पाबाट पहाडमुनि बस्ने मानिसलाई देखे झैं देख्दछ ।",
  "29": "प्रमादीहरूमा अप्रमादी, निद्रालुहरूमा अनिद्रालु र बलहीन घोडामा सबल घोडा अगाडि गए झैं, बुद्धिहीन व्यक्तिहरूमध्ये बुद्धिमान् पूर्वगामी हुन्छ ।",
  "30": "अप्रमादी हुनाले (इन्द्र) देवताहरूका राजा भए, अप्रमादको प्रशंसा हुन्छ, प्रमादको सधैँभरि निन्दा हुन्छ ।",
  "31": "प्रमादमा डर मानी अप्रमादमा मन लगाउने भिक्षुले, फेरि-फेरि जन्म लिनुपर्ने सानो-ठूलो जुनसुकै संयोजनलाई पनि आगोले भस्म गरे झैं भस्म गर्दछ ।",
  "32": "प्रमादमा डर मानी अप्रमादमा मन लगाउने भिक्षुको खराब गति हुँदैन; ऊ निर्वाणको नजिकै आइपुग्दछ ।",
  "chap3": "चित्तवग्गो",
  "33": "बुद्धिमान् व्यक्तिले बाणकारले बाण सोझो पारे झैं आफ्नो चञ्चल तथा रक्षा गर्न गाह्रो चित्तलाई तह लगाउँछ ।",
  "34": "जसरी पानीबाट झिकेर सुक्खा जमिनमा राख्दा माछा छटपटाउँछ, त्यसरी नै मारको जालबाट छुटाउँदा यो चित्त छटपटाउँछ ।",
  "35": "क्षण-क्षणमा उत्पन्न हुने, रोक्न गाह्रो, जताततै दगुर्ने, स्वेच्छाचारी चित्तलाई दमन गर्नु बेस हुन्छ; चित्त दमन गर्नाले नै सुख पाइन्छ ।",
  "36": "पण्डित हो! अगोचर, सूक्ष्म र मन परेको ठाउँमा जाने चित्तलाई रक्षा गर, चित्तलाई वशमा राख्यो भने सुख पाइन्छ ।",
  "37": "टाढा-टाढासम्म पुग्न सक्ने, एक्लै हिँड्ने, विनाशरीरको गुफामा बस्ने चित्तलाई वशमा राख्न सक्ने व्यक्ति मारको बन्धनबाट मुक्त हुन्छ ।",
  "38": "चित्त स्थिर नभएको, सद्धर्म नजान्ने र प्रसन्न स्वभाव नभएको व्यक्तिलाई प्रज्ञा-ज्ञान पूर्ण रूपले प्राप्त हुन सक्दैन ।",
  "39": "अनासक्त, स्थिरचित्त र जाग्रत चित्त भई पुण्य र पाप दुवै नभएको व्यक्तिलाई भय हुने छैन ।",
  "40": "शरीरलाई माटाको भाँडो सम्झी, चित्तलाई नगर झैं सुरक्षित राखेर प्रज्ञारूपी शस्त्र लिएर मारसँग युद्ध गर, मारलाई जितेर पनि अनासक्त भई आफ्नो चित्तलाई रक्षा गरिराख्नु ।",
  "41": "चाँडै नै यो शरीर विज्ञानरहित भै काम नलाग्ने काठको मुढा झैं भूमिमा लडिरहने छ ।",
  "42": "शत्रुले शत्रुलाई जति हानि पुऱ्याउन सक्छ, त्यो भन्दा बढी हानि कुमार्गमा लागेको चित्तले पुऱ्याउँछ ।",
  "43": "सुमार्गमा लागेको चित्तले आफूलाई जति उपकार गर्दछ, त्यति उपकार बाबु-आमा र कुटुम्बले समेत गर्न सक्दैनन् ।",
  "chap4": "पुप्फवग्गो",
  "44": "यमलोक, देवलोक सहितको यो पृथ्वीलाई कसले जित्न सक्तछ ? चतुर मालीले फूल छाने झैं राम्रोसँग देशित धर्मपद कसले रोज्न सक्ला ?",
  "45": "यमलोक, देवलोक सहितको यो पृथ्वीलाई शैक्षले जित्ला, चतुर मालीले झैं राम्रोसँग देशित धर्मपद शैक्षले रोज्ला ।",
  "46": "शरीरलाई पानीको फीँज समान अथवा मृगतृष्णा समान सम्झेर पण्डितहरू मारबन्धनबाट मुक्त भई मारले नदेख्ने ठाउँमा पुग्दछन् ।",
  "47": "पञ्चकाम इन्द्रियरूपी फूल टिप्नमा आसक्त भई रहने व्यक्तिलाई, बाढीले सुतिरहेका ग्रामवासीहरूलाई बगाएर लगे झैं मृत्युले लैजान्छ ।",
  "48": "पञ्चकाम इन्द्रियरूपी फूल टिप्नमा व्यस्त भई रहने व्यक्तिलाई आफ्नो तृष्णा पूरा नहुँदै मृत्युराजले वशमा राख्दछ ।",
  "49": "भमराले फूलको रङ्ग-रूप नबिगारिकन त्यसको रस चुसेर गए झैं मुनिहरू ग्राममा विचरण गर्दछन् ।",
  "50": "अर्काको दोष र अर्काले के गर्यो के गरेन भनी हेर्नुभन्दा आफ्नो दोष र आफूले के गरेँ के गरिन भनी हेर्नु नै बेस छ ।",
  "51": "जस्तो वास नआएको फूल राम्रो भएता पनि निष्फल हुन्छ, त्यस्तै क्रियाहीन कुरा पनि निष्फल हुन्छ ।",
  "52": "सुगन्ध भएको राम्रो फूलको कदर भए झैं क्रियायुक्त कुरा सफल हुन्छ ।",
  "53": "मालीले धेरै फूलबाट छानी-छानी राम्रो माला गाँसे झैं संसारमा जन्मने मानिसले धेरै कुशल कर्म गर्नुपर्छ ।",
  "54": "फूल, चन्दन, चमेली आदिको वास हावा नपुगेको ठाउँमा जान सक्दैन, किन्तु सत्पुरुषको सौजन्यरुपी सुगन्ध दशैं दिशामा फैलिन्छ ।",
  "55": "चन्दन, तगर, कमल, चमेली आदिको सुगन्धभन्दा शील-गुणको सुगन्ध उत्तम हुन्छ ।",
  "56": "तगर, चन्दनादिको सुगन्ध कम्ती छ, शीलवान्हरूको सुगन्ध देवलोकसम्म पनि फैलिन्छ ।",
  "57": "शीलवान् र अप्रमादी भएर चित्तलाई क्लेशबाट मुक्त गराएर बस्ने व्यक्तिको मार्ग मारले पत्ता लगाउन सक्दैन ।",
  "58": "जसरी सडकको किनारमा फ्याँकिएको फोहरको थुप्रोमा सुगन्धित र मनमोहक कमलको फूल उम्रन्छ,",
  "59": "त्यसरी नै, अज्ञानी र क्लेशयुक्त सांसारिक मानिसहरूको बीचमा बुद्धका शिष्यहरू आफ्नो प्रज्ञाले देदिप्यमान भएर चम्कन्छन्।",
  "chap5": "बालवग्गो",
  "60": "निन्द्रा नआउनेलाई रात लामो जस्तो लाग्ने, थाकेकालाई एक योजनको बाटो पनि टाढा जस्तो लाग्ने हुन्छ; त्यस्तै सद्धर्म नजान्ने अज्ञानी मूर्खलाई संसारको बाटो लामो लाग्दछ ।",
  "61": "भरसक आफूभन्दा गुणी मानिसको सत्सङ्गत गर्नु, नभए आफू समानको सत्सङ्गत गर्नु; तर आफूभन्दा दुर्गुणीको सङ्गत कहिल्यै नगर्नु । यस्ताको सङ्गत गर्नुभन्दा त सुदृढ मन राखी एक्लै हिँड्नु जाति छ ।",
  "62": "'मेरो छोरा छ', 'धन छ' भनी अज्ञानीहरू चिन्तित हुन्छन् । आफ्नो देह नै आफूले भनेजस्तो छैन भने छोरा भएर के! धन भएर के!",
  "63": "आफ्नो मूर्खतालाई चिन्न सक्ने मानिस नै पण्डित कहलाइन्छ; मूर्ख भइकन पनि 'पण्डित हुँ' भन्नेलाई मूर्ख भन्दछन् ।",
  "64": "तरुनी (तरकारी) को स्वाद थाहा नभए झैं, मूर्खजनले पनि जीवनभर पण्डितको सत्सङ्गत गरेता पनि धर्मको मर्म बुझ्न सक्दैनन् ।",
  "65": "जिब्रोले तरकारीको स्वाद पाए झैं विज्ञजनले, क्षणमात्र भए पनि पण्डितहरूको सत्सङ्गत पायो भने धर्मको रस बुझिहाल्छ ।",
  "66": "मूर्खहरूले आफैंलाई शत्रु बनाएर पाप कर्म गर्छन्! त्यही पाप कर्मको कटु फल पछि आफैंलाई प्राप्त हुन्छ ।",
  "67": "जुन कामको फल भोग गर्दा आँसु बगाई पछुतो गर्नुपर्ला, त्यस्तो काम सज्जनले नगर्नु नै बेस हो ।",
  "68": "जुन कामको फल भोग गर्दा पछुतो गर्नुपर्दैन, चित्त प्रसन्न रहन्छ, सज्जनले त्यस्तो काम गर्नुपर्दछ ।",
  "69": "पापको फल भोग गर्न नपरेसम्म मूर्खले आफूले गरेको खराब कामलाई मह जस्तो ठान्दछ, तर पापको फल भोग्नुपर्दा दुःखित हुन्छ ।",
  "70": "महिनामा एकपल्ट मात्र कुश-अग्रले (कुशको टुप्पोले) भोजन गरेता पनि, मूर्खहरू पण्डितको अगाडि सोह्रै आनामा एक आना पनि मूल्यवान् हुन सक्दैनन् ।",
  "71": "दुहुनासाथ दूध बिग्रँदैन, त्यस्तै पापको फल पनि तुरुन्तै आउँदैन । खरानीको आगोले क्रमशः पोले झैं, पापले मूर्खलाई क्रमशः पोल्दै ल्याउँछ ।",
  "72": "मूर्खको बुद्धि अनर्थ गर्ने हुन्छ । मूर्खले आफ्नो मूर्खताको कारण आफ्नो सुख हुने भविष्यलाई, आफ्नै शिर फोरे झैं गरेर बिगार्दछ ।",
  "73": "खराब विचार हुने भिक्षुले यस्तो इच्छा गर्दछ: 'म भिक्षुगणमाथि बसूँ, मठ र विहारको अधिपति होऊँ, अर्काको घरमा पूजित होऊँ, सबै काम आफूले भने झैं होस्'।",
  "74": "यस्ता सङ्कल्प गर्ने भिक्षुको मनमा तृष्णा र अभिमान बढ्दै जान्छ।",
  "75": "लाभ-सत्कार पाइने बाटो अर्कै, निर्वाण पाइने बाटो अर्कै सम्झेर बुद्ध-शासनमा बस्ने भिक्षुले समाजमा लाभ-सत्कारको वास्ता नराखी एकान्तवासी हुने चर्या बढाउनुपर्दछ ।",
  "chap6": "पण्डितवग्गो",
  "76": "आफ्नो दोष देखाइदिनेलाई गाडेको धन देखाइदिने मित्र भनी ठान्नुपर्छ, ज्ञानीहरू आफूलाई गाली गरेर सिकाउनेको सत्सङ्गत छोड्दैनन्, त्यस्ताको सत्सङ्गत गर्नाले आफ्नो उन्नति सिवाय हानि हुँदैन ।",
  "77": "उपदेश देऊ, आफूलाई अनुशासन गर, असभ्य स्वभाव छोड भन्ने मानिस सत्पुरुषहरूको प्रेमपात्र हुन्छ । उसलाई असत्पुरुषले रुचाउँदैन ।",
  "78": "पापी मित्र र अधर्म पुरुषको सङ्गत नगर, कल्याण मित्र र उत्तम पुरुषको सत्सङ्गत गर ।",
  "79": "धर्म-रस बुझ्ने व्यक्ति प्रसन्न चित्त भई आरामपूर्वक निदाउँछ, पण्डितहरू सधैं आर्य धर्ममा मन लगाउँछन् ।",
  "80": "कुलो खन्नेले आफूलाई चाहिँदो ठाउँमा पानी लैजान्छ, बाण बनाउनेले आफूलाई चाहिए बमोजिम बाण बनाउँछ, सिकर्मीले पनि आफूलाई चाहिए बमोजिमको काठ बनाउँछ; त्यस्तै पण्डितहरूले पनि आफूलाई चाहिए बमोजिम आत्मदमन गर्दछन् ।",
  "81": "ठूल्ठूला ढुङ्गालाई हावाले उखेल्न नसके झैं निन्दा र प्रशंसाले पण्डितहरूलाई विचलित गराउन सक्दैन ।",
  "82": "अगाध तथा गम्भीर पोखरीको पानी निर्मल भएजस्तै, पण्डितहरूको चित्त धर्मश्रवणको प्रभावले स्वच्छ र निर्मल हुन्छ ।",
  "83": "सत्पुरुषहरूले सबै कुरा त्याग गर्छन्, शान्त भएर काम-विषयक कुरा केही गर्दैनन्, सुख होस् वा दुःख होस्, त्यस विषयमा केही पनि बोल्दैनन् ।",
  "84": "आफ्नो निमित्त, अर्काको निमित्त, सन्तानको आशा, अथवा धन र राज्यको निम्ति अधर्मबाट समृद्ध हुन्छु भन्ने विचार नराख्ने, यस्तालाई नै धार्मिक भन्दछन् ।",
  "85": "यो संसाररूपी समुद्रदेखि उता पार जाने मानिस थोरै हुन्छन्, अरू बाँकी सबै यतै तीरैतीरमा दगुरी रहने हुन्छन् ।",
  "86": "राम्रोसँग देशना गरिएको सद्धर्मअनुसार आचरण गर्ने व्यक्ति नै यस्तो दुस्तर सागरको पार तरेर जान्छ ।",
  "87": "भिक्षु हो, खराब धर्मलाई छोडी असल धर्म ग्रहण गर्नुपर्छ, घर छाडेर त्यागी हुनेले एकान्त-सेवन गर्नुपर्छ ।",
  "88": "कामभोग सबै छोडी नैष्कर्म्यमा रत हुनुपर्दछ, पण्डितले आफ्नो मनको मैला सबै फ्याँकेर आफूलाई परिशुद्ध बनाउँछ ।",
  "89": "सम्बोध अङ्गमा मन बसिसकेका, परिग्रहलाई त्यागेर अपरिग्रहमा लागेका, मैला रहित चित्त भएका यस्ता तेज सम्पन्न पुरुषलाई नै निर्वाण-पद प्राप्ति भएको हुन्छ ।",
  "chap7": "अरहन्तवग्गो",
  "90": "आफ्नो मार्ग तय गरिसकेको, शोक रहित भएर सबै गाँठो फुस्किसकेको, त्यस्ता व्यक्तिलाई शोक-सन्ताप हुँदैन ।",
  "91": "जसले स्मृतिवान् भएर उद्योग गर्दछ, गृहस्थ जीवनमा रमाउन छोड्दछ, त्यस्ता व्यक्तिले जस्तो हंसले क्षुद्र जलाशय छोडेर जान्छ, त्यस्तै गरी गृहत्याग गरिदिन्छ ।",
  "92": "जसको संग्रह छैन, जो भोजनमा संयमी छ र शून्यस्वरूप निर्वाणमा दत्तचित्त छ, त्यस्ताको गति आकाशमा उड्ने पंक्षीको गति जस्तो देख्न गाह्रो हुन्छ ।",
  "93": "जसको आस्रव क्षीण भइसकेको छ, आहारमा आसक्ति छैन, शून्यस्वरूप निर्वाणमा दत्त-दृष्टि छ, त्यस्ताको गति आकाशमा उड्ने पंक्षीको गति जस्तै देख्न गाह्रो हुन्छ ।",
  "94": "सवारले दमन गरेको घोडा झैं जसको इन्द्रिय शान्त भइसकेको छ, त्यस्ता निरभिमानी अनास्रवी सन्तको स्पृहा देवताहरूले पनि गर्दछन् ।",
  "95": "पृथ्वी समान र इन्द्रकील समान नडगी बस्ने व्यक्तिको मन निर्मल, पङ्क-रहित (हिलो नभएको) जलाशय झैं स्वच्छ भएर संसारका अनेक ग्रन्थीहरूमा अल्झिएको हुँदैन । त्यस्ता अर्हत्को पुनर्जन्म हुँदैन ।",
  "96": "राम्रोसँग जानीबुझी मुक्त भइसकेको अर्हत् पुरुषको मन शान्त हुन्छ, वाणी तथा कर्म पनि शान्त हुन्छ ।",
  "97": "अन्धविश्वास रहित, निर्वाणका ज्ञानी, जन्म-मरण रहित भएर सबै तृष्णा त्याग गरिसकेको मानिसलाई उत्तम पुरुष भनिन्छ ।",
  "98": "गाउँ, जङ्गल, मैदान, पहाड आदि जुन ठाउँमा अर्हत्हरू विहरण गर्दछन्, त्यो ठाउँ रमणीय हुन्छ ।",
  "99": "रमणीय जङ्गल जहाँ विषयासक्त साधारण जन बस्न रुचाउँदैनन्, त्यहाँ काम-भोगको पीछा छाड्ने वीतरागी मात्र बस्न रुचाउँछन् ।",
  "chap8": "सहस्सवग्गो",
  "100": "अर्थ न ब्यर्थका पद भएका सहस्र वाक्य बोल्नुभन्दा सार्थक पद एउटा नै श्रेष्ठ छ, जुन सार्थक पद सुन्नाले शान्ति मिल्दछ ।",
  "101": "अर्थ न ब्यर्थका पद भएका सहस्र गाथा पढ्नुभन्दा सार्थक गाथा एउटा नै श्रेष्ठ छ, जुन सार्थक गाथा पढ्नाले शान्ति मिल्दछ ।",
  "102": "अर्थ रहित हजार श्लोक पढ्नुभन्दा अर्थ सहित शान्ति प्राप्त हुने एउटा धर्मपद पढ्नु बेस छ ।",
  "103": "लडाइँमा हजारौँलाई जित्नुभन्दा आफूलाई जित्न सक्नेलाई नै संग्रामजित् भन्दछन् ।",
  "104": "अर्कालाई जित्नुभन्दा आफूलाई जित्नु श्रेष्ठ हो।",
  "105": "किनभने आत्मदमन गरी सदा संयमी हुने व्यक्तिलाई देव, गन्धर्व, मार तथा ब्रह्माले पनि जित्न सक्दैनन्।",
  "106": "महिना-महिनामा हजारौँ रूपियाँ खर्च गरी यज्ञ-होम गर्नुभन्दा क्षणभर मात्र भएता पनि संयमी व्यक्तिलाई पूजा-सत्कार गर्नु बेस; सय वर्ष होम गरेभन्दा क्षणभर गरेको पूजा नै श्रेष्ठ हो ।",
  "107": "सय वर्षसम्म जङ्गलमा बसी यज्ञ गर्नुभन्दा क्षणभर भएतापनि इन्द्रिय-संयमी व्यक्तिलाई पूजा-सत्कार गर्नु बेस, किनभने सय वर्ष यज्ञ गरेभन्दा क्षणभर गरेको पूजा नै श्रेष्ठ हो ।",
  "108": "पुण्यको इच्छा गरी जुनसुकै यज्ञ-होम वर्ष दिनसम्म गरेतापनि ऋजुभूत सन्तलाई गरेको अभिवादनको चौथाई भाग बराबरको फल पनि पाउन सक्दैनन् ।",
  "109": "अभिवादन गर्ने स्वभाव हुने र सधैँ वृद्धहरूको सेवा-सुश्रूषा गर्ने व्यक्तिको चार थोक बढ्दछ – आयु, वर्ण, सुख र बल ।",
  "110": "दुराचारी र असमाहित पुरुषको सय वर्षको जीवनभन्दा सदाचारी र ध्यानी पुरुषको एक दिनको जीवन नै बेस छ ।",
  "111": "बुद्धिहीन असमाहित पुरुषको सय वर्षको जीवनभन्दा ध्यानी प्रज्ञावान्‌को एकै दिनको जीवन बेस छ ।",
  "112": "अल्सी, वीर्यहीन भई सय वर्ष जिउनुभन्दा दृढ उद्योगी भई एकै दिन जिउनु बेस हुन्छ ।",
  "113": "उत्पत्ति र विनाशको ज्ञान बिर्सेर सय वर्ष जिउनुभन्दा उत्पत्ति र विनाशको ज्ञान जानेर एकै दिन जिउनु बेस हुन्छ ।",
  "114": "अमृतपदलाई बिर्सेर सय वर्ष जिउनुभन्दा अमृतपदलाई जानेर एकै दिन जिउनु बेस हुन्छ ।",
  "115": "उत्तम धर्म नजानेर सय वर्ष जिउनुभन्दा उत्तम धर्म जानेर एकै दिन जिउनु बेस हुन्छ ।",
  "chap9": "पापवग्गो",
  "116": "पापमा चित्त लगायो भने पापमा चित्त जाने सम्भावना हुन्छ ।",
  "117": "मानिसले पाप गरिहाल्यो भने पनि फेरि-फेरि गर्नु हुँदैन । पापमा इच्छा बढाउनु हुँदैन, पाप थुप्रियो भने दुःखको कारण बन्न जान्छ ।",
  "118": "पुण्य गरिसक्यो भने फेरि पनि गर्नुपर्छ, त्यसमा खूब उत्साह बढाउनुपर्छ; पुण्यको रास सुखको कारण हो ।",
  "119": "पापको फल नपाएसम्म पापीले पाप गर्नु बेस सम्झन्छ, पापको फल पाएपछि मात्रै उसलाई पापको पूरा परिचय हुन्छ ।",
  "120": "पुण्यात्माले पनि पुण्यको फल नआएसम्म पुण्य खराब सम्झन्छ, पुण्यको फल आएपछि मात्रै उसलाई पुण्यको पूरा परिचय हुन्छ ।",
  "121": "अलिकति पाप गरेर के होला भनी नसोच्नु, एक-एक थोपा गरेर पानीले गाग्री भरे झैं मूर्खजनले पनि अलि-अलि गरेर पाप थुपार्छ ।",
  "122": "अलिकता पुण्य गरेर के होला भनी नभन्नु, एक-एक थोपा पानीले गाग्री भरे झैं धीर पुण्यवान्ले अलि-अलि गरेर पुण्य थुपार्छ ।",
  "123": "हतियार नहुने महाधनी व्यापारीले भययुक्त बाटो छोडे झैं अथवा जिउने इच्छा हुनेले विषलाई छोडे झैं, मनुष्यले पाप गर्न छोड्नुपर्छ ।",
  "124": "हातमा घाउ नहुनेले विष छोएता पनि विष नलागे झैं, पाप नगर्नेलाई पापले छुँदैन ।",
  "125": "जताबाट हावा बहेको छ उतातिर धुलो फ्याँक्दा आफैतिर आए झैं, निर्दोष, शुद्ध, क्लेश-रहित पुरुषलाई गरेको दोषारोपणको प्रतिफल आफैंलाई पर्न आउँछ ।",
  "126": "कोही संसारमा जन्मन्छ, कोही पापी नरकमा जन्मन्छ, पुण्यवान्‌ले स्वर्गमा जन्म लिन्छ, चित्त-मलरहित अनास्रव व्यक्तिलाई निर्वाण प्राप्ति हुन्छ ।",
  "127": "आकाश, समुद्र तथा पर्वतको गुफामा जहाँ गएर बसे तापनि आफूले गरेको पापको फलबाट बच्न सकिँदैन ।",
  "128": "आकाश, समुद्र वा पर्वतको गुफा होस्, जहाँ गएर बसे तापनि मृत्युबाट बच्न सकिँदैन ।",
  "chap10": "दण्डवग्गो",
  "129": "दण्ड देखेर सबै डराउँछन्, मृत्यु देखेर सबै काँप्दछन्, त्यसकारण आफू झैं सम्झी प्राणीलाई हिंसा नगर्नु र नगराउनु ।",
  "130": "दण्ड देखेर सबै डराउँछन्, सबैलाई ज्यानको माया छ, त्यसकारण आफू झैं सम्झी प्राणीलाई आघात नगर्नु र नगराउनु ।",
  "131": "आफ्नो सुखको लागि सुखकामी प्राणीलाई जसले दण्डद्वारा हिंसा-पीडा दिन्छ, त्यसले परलोकमा सुख पाउँदैन ।",
  "132": "आफ्नो सुखको लागि सुखकामी प्राणीलाई जसले दण्डद्वारा हिंसा-पीडा दिँदैन, त्यसलाई परलोकमा सुख प्राप्ति हुन्छ ।",
  "133": "कठोर वचन नबोल, अरूले पनि तिमीलाई उत्तिकै कडा वचन बोल्नेछ; कडा वचन बोल्नाले त्यसको बदला दण्ड पाउनेछौ ।",
  "134": "फुटेको काँसको थाल झैं निःशब्द हुन सक्यौ भने तिमीलाई निर्वाण प्राप्ति हुन्छ । तिम्रो निम्ति कलह (हिंसा) केही हुने छैन ।",
  "135": "गोठालाले लट्ठी लिएर गाई धपाउँदै लगे झैं बुढ्यौली र मृत्युले प्राणीको आयुलाई धपाउँदै लैजान्छ ।",
  "136": "मूर्खलाई पाप गर्दा दुःख हुन्छ भन्ने ज्ञान हुँदैन; पछि आफ्नो कर्मको फल भोग्ने बेलामा उसलाई आगोले झैं पोल्ने पछुतो हुन्छ ।",
  "137": "दण्डरहितलाई दण्ड र दोषरहितलाई दोष दिने व्यक्तिलाई निम्नलिखित दश प्रकारका दुःखमध्ये कुनै न कुनै दुःख हुन्छ।",
  "138": "(१) टाउको दुख्ने आदि असह्य वेदना हुन्छ, (२) आफ्नो भएको धन विनाश हुन्छ, (३) अङ्गभङ्ग हुन्छ, (४) ठूल्ठूलो रोग हुन्छ।",
  "139": "(५) बहुलाउने हुन्छ, (६) राजदण्डादिको भय हुन्छ, (७) ठूलो निन्दा हुन्छ, (८) ज्ञाति-बन्धुहरूको विनाश हुन्छ।",
  "140": "(९) आफ्नो भोगको विनाश हुन्छ, (१०) घरमा आगलागी हुन्छ तथा मृत्यु भई नरक बास हुन्छ।",
  "141": "नाङ्गो बसेर, जटा पालेर, हिलोमा लडबडिएर, भोको बसेर, भुइँमा सुतेर, खरानी दलेर बस्दैमा शङ्का निवारण नगर्नेले आत्मा शुद्ध पार्न सक्दैन ।",
  "142": "गहना र वस्त्रले सिङ्गारिएर पनि यदि शान्त, दान्त, नियम-तत्पर, ब्रह्मचारी तथा सबै प्राणीको उपर दण्ड दिने कुत्सित विचारलाई त्याग गर्न सक्यो भने त्यो ब्राह्मण, त्यो श्रमण, त्यो भिक्षु हो ।",
  "143": "निषिद्ध कर्म मानिस यो लोकमा कोही-कोही मात्र हुन्छ, असल घोडाले कोर्रा बचाए झैं उनीहरूले निन्दाबाट आफूलाई बचाउँछन् ।",
  "144": "कोर्राको चोट सहन नसक्ने असल घोडा झैं तिमीहरू पनि प्रयत्नशील र वेगवान् होऊ! श्रद्धा, शील, वीर्य, समाधि र धर्म-विनिश्चयले युक्त भई विद्यावान्, आचारवान्, स्मृतिवान् भई यो महान् दुःख राशिलाई मेरैसित पार गर ।",
  "145": "कुलो खन्नेले आफूलाई चाहिएको ठाउँमा पानी लैजान्छ, बाणकारकले आफूलाई चाहिएबमोजिम बाण बनाउँछ, सिकर्मीले आफूलाई चाहिएबमोजिम काठ तयार गर्छ र त्यस्तै धर्म-निरत व्यक्तिले आफूलाई दमन गर्दछ ।",
  "chap11": "जरावग्गो",
  "146": "चारैतिर आगो दन्दन बलिरहेको छ, कसरी हाँस्नु, कसरी आनन्द लिनु? अन्धकारले चारैतिर घेरिसकेको छ, तैपनि किन आलोक (प्रकाश) खोज्दैनौ?",
  "147": "जुन शरीर अस्थिर छ, घाउ-दर्दले पूर्ण छ, नानाविधि सङ्कल्पले भरिपूर्ण छ, छापामार झैं सिँगारिएको यो विचित्र शरीर हेर!",
  "148": "यो रूप जीर्ण भएर जाने, रोगको घर हो, अत्यन्त क्षणभङ्गुर, गन्हाउने शरीर छुटेर मरणमा जीवनको अन्त हुन्छ ।",
  "149": "शरद ऋतुमा फ्याँकिएको काम नलाग्ने लौका, परेवा झैं सेतो हाडरूपी शरीरलाई देखेर कसलाई प्रेम लाग्ला?",
  "150": "हाडको नगर बनाई त्यसमा मासु र रगतको लेप लगाएको, जसमा वृद्धत्व, मृत्यु, अभिमान, कपट आदि लुकाइएका छन् ।",
  "151": "सुसज्जित राजाको रथ जीर्ण भएर गए झैं यो देह पनि जीर्ण भएर जान्छ, तर साधु-सन्तको धर्म जीर्ण हुँदैन; सन्तहरू सन्तका अगाडि यही कुरा बताउँछन् ।",
  "152": "अज्ञानी मानिस गोरु झैं बढ्दछ; मासु मात्र बढ्छ, प्रज्ञा बढ्दैन ।",
  "153": "अनेक जन्म बित्यो गृह निर्माण गर्नेलाई खोज्दा-खोज्दै! मेरो हरएक जन्म दुःखमय भएर बित्यो।",
  "154": "अब हे गृह निर्माण गर्ने बुद्धि हो! मैले तँलाई देखिसकेँ, फेरि तैंले घर बनाउन सक्ने छैनस्। तेरो घर बनाउने काठपात जम्मै भाँचिसकेँ, घरको धुरी पनि खसालिदिएँ; मेरो चित्त संस्कार-रहित भई तृष्णाको विनाश भई सक्यो।",
  "155": "यौवनावस्थामा धन नकमाएर, ब्रह्मचर्य पालन नगरी बस्ने व्यक्तिले माछा नभएको पोखरीमा ढुकेर क्रौञ्च पक्षीले जीवन सित्तै फाले झैं आफ्नो जीवन खेर फाल्नुपर्छ ।",
  "156": "यौवनावस्थामा धन नकमाएर, ब्रह्मचर्य पालन नगरी बस्ने व्यक्तिले फ्याँकिएको पुरानो धनुषले झैं बितेका घटनाहरूको मात्र चिन्ता गरेर अपसोस गर्नुपर्छ ।",
  "chap12": "अत्तवग्गो",
  "157": "तिम्रो आफ्नो उपर प्रेम छ भने आफूलाई सुरक्षित (संयत) गर! पण्डितजनले तीन प्रहरमध्ये कुनै एक प्रहरमा जागारहनु पर्दछ ।",
  "158": "सर्वप्रथम आफूलाई उचित मार्गमा लगाउनु, अनि पछि मात्रै अरूलाई उपदेश गर्नु; यसो गर्नाले पण्डितलाई क्लेश हुने छैन ।",
  "159": "अरूलाई अनुशासन गर्नु छ भने पहिले आफैं त्यस्तो बनी दिनुपर्दछ । आफूलाई दमन गर्नुपर्दछ; आत्म-दमन गर्नु नै ज्यादै गाह्रो कुरा हो ।",
  "160": "आफू नै आफ्नो मालिक हो, आफ्नो मालिक अरू को हुनसक्ला? आफूलाई राम्रोसँग दमन गर्न सक्यो भने दुर्लभ स्वामित्व प्राप्ति हुन्छ ।",
  "161": "आफूले गरेको पापले आफैंलाई पीडा दिन्छ; मूर्खजनलाई आफैंले गरेको पापले, पत्थरबाट निस्कने हीराले आफूबाट निस्केका ढुङ्गालाई नै काट्ने झैं पिरोल्छ ।",
  "162": "मालुवा भन्ने लहराले झ्याम्म छोपेको शालवृक्ष झैं, जसको दुराचार फैलिएको छ, त्यस दुर्बुद्धि मनुष्यले आफूलाई शत्रुले जस्तो गर्न चाहेको छ उस्तै बनाउँछ ।",
  "163": "आफूलाई खराब हुने अहित कर्म गर्नु साह्रै सजिलो हुन्छ, आफूलाई हित हुने काम गर्नु बडो मुस्किल छ ।",
  "164": "जसले आफ्नो मिथ्या धारणको कारण धर्मात्मा श्रेष्ठ अर्हन्तहरूलाई निन्दा गर्दछ, त्यसले आफैंलाई नाश गर्दछ, जस्तो फूलले बाँसलाई नाश गर्दछ ।",
  "165": "आफूले गरेको पापले आफैंलाई अपवित्र पार्दछ, आफूले गरेको पुण्यले आफैंलाई शुद्ध पार्दछ । शुद्धि हुने र अशुद्धि हुने आफ्नै द्वारबाट हो; कसैले अरू कसैलाई शुद्ध पार्न सक्दैन ।",
  "166": "अर्काको खूबै हित गर्नका लागि आफ्नो हितको हानि गर्नु हुँदैन; आफ्नो हितको विचार राखेर सदर्थमा लाग्नुपर्दछ ।",
  "chap13": "लोकवग्गो",
  "167": "नीच धर्म सेवन नगर, प्रमादी नहोऊ, मिथ्या धारणमा नफँस, आवागमन (फेरि-फेरि जन्म लिने) को कामना नबढाऊ ।",
  "168": "उठ, प्रमादी नहोऊ, सद्धर्मको आचरण गर, धार्मिक पुरुषहरू इहलोक-परलोक दुवैमा सुखपूर्वक जीवन बिताउँछन् ।",
  "169": "धर्म आचरण राम्रोसँग गर्नुपर्छ, दुराचरण गर्नु हुँदैन; धर्माचरण गर्ने पुरुषले इहलोक-परलोक दुवैमा सुखपूर्वक जीवन बिताउँछ ।",
  "170": "यस संसारलाई पानीमा उठेका फोका अथवा मृगतृष्णा समान भनी बराबर सम्झेर बस्नेलाई यमराजले देख्दैन ।",
  "171": "आऊ, हेर यो भड्किलो राजाको रथ जस्तो संसारलाई; यसमा मूर्खजन मात्र फस्दछ, ज्ञानीजन आसक्त हुँदैनन् ।",
  "172": "जो पहिले प्रमादी भई, पछि त्यो फेरि प्रमादी बन्दैन – त्यस्ताले यो लोकमा बादलबाट छुटेको चन्द्रमाले झैं तेज फैलाउँछ ।",
  "173": "जसले पापकर्मलाई पुण्य कर्मले ढाक्छ, त्यसले यो लोकमा बादलबाट छुटेको चन्द्रमाले झैं तेज फैलाउँछ ।",
  "174": "यो संसार अन्धो छ, आँखा हुने मानिस थोरै मात्र छन्; जालबाट मुक्त हुने चराहरू जस्तै थोरै मात्र स्वर्ग जान्छन् ।",
  "175": "हंसहरू सूर्य पथ (आकाश) मा उड्छन्, ऋद्धिद्वारा योगी पनि आकाश मार्गमा भ्रमण गर्दछन्, तर ससैन्य मारलाई जितेर बुद्धिमान् पण्डितहरू यस लोकबाट पार भएर जान्छन् ।",
  "176": "धर्म छोडेर झूटो बोल्ने र परलोकको चिन्ता नगर्नेले, गर्न नसक्ने पाप यस लोकमा छँदै छैन ।",
  "177": "कृपणीहरू देवलोकमा जाँदैनन्, मूर्खहरू दानको प्रशंसा गर्दैनन्; धीर पण्डितहरू दानको अनुमोदन गरेर दानको पुण्यले परलोकमा सुख प्राप्त गर्दछन् ।",
  "178": "पृथ्वीको राज्य, स्वर्ग जान पाउने भाग्य अथवा सारा संसारको आधिपत्यभन्दा पनि उत्तम 'स्रोत-आपत्ति' फलको प्राप्ति हो ।",
  "chap14": "बुद्धवग्गो",
  "179": "जसको विजय फेरि पराजय हुन सक्दैन, जसलाई जितिसकेको राग-द्वेषादिले फेरि पिछा गर्न सक्दैन, जसलाई मार्गको प्रयोजन छैन, उस्ता ज्ञानी अनन्तका मार्ग-रहित बुद्धलाई कुन बाटो लैजान्छौ?",
  "180": "जसलाई बन्धनमा जकड्ने विषरूपी तृष्णाले कहीँ पनि लैजान सक्दैन, उस्ता ज्ञानी अनन्तका पथ-रहित बुद्धलाई कुन बाटो लैजान्छौ?",
  "181": "धीर भई ध्यानमा लागेका, शान्तिको मार्ग नैष्क्रम्यमा बस्ने बुद्धहरूको देवताहरूले पनि स्पृहा गर्दछन् ।",
  "182": "मनुष्य भएर जन्म लिनु दुर्लभ छ, जन्मे र पनि जीवित रहनु कठिन छ । जीवित रहे पनि धर्मश्रवण गर्नु कठिन छ तथा बुद्धको जन्म हुनु पनि दुर्लभ छ ।",
  "183": "कुनै पाप नगर्नु, पुण्य संचय गर्नु र आफ्नो चित्तलाई शुद्ध गर्नु – यही बुद्धहरूको शिक्षा हो ।",
  "184": "सहनशीलता र क्षमाशीलता परम तप हुन्, बुद्धहरू निर्वाणलाई परमपद भन्दछन् । अर्कालाई घात गर्ने, अर्कालाई पीडा दिने प्रव्रजित सच्चा साधु होइनन् ।",
  "185": "कसैलाई निन्दा वा हिंसा-पीडा नगर्नु, प्रातिमोक्षका शीलहरू पालन गर्नु, आहारमा मात्राको ज्ञान राख्नु, एकान्त बास गर्नु र चित्त-शुद्धिको निम्ति योग गर्नु – यही बुद्धहरूको शिक्षा हो ।",
  "186": "रुपियाँ-पैसा वर्षाए तापनि मानिसको काम-तृष्णाहरू तृप्त हुँदैनन्।",
  "187": "पण्डितजनहरू 'संसारिक काम-भोगादिमा अल्पमात्र स्वाद छ, उल्टो धेरै दुःख छ' भन्ने जानेर काम-सुखको इच्छा गर्दैनन्; सम्यक्सम्बुद्धका श्रावकहरू तृष्णाक्षय गर्नमा लाग्दछन्।",
  "188": "डरका कारण मनुष्यहरू पर्वत, वन, उद्यान, वृक्ष र तीर्थ-स्थानको शरण लिन जान्छन्, किन्तु यो शरण मङ्गलदायक होइन।",
  "189": "यो उत्तम शरण पनि होइन, कारण, यस्तो शरणले सबै प्रकारको दुःखबाट छुटकारा पाइँदैन।",
  "190": "जो बुद्ध, धर्म तथा संघको शरण लिन जान्छ।",
  "191": "जसले दुःख, दुःखको उत्पत्ति, दुःख-निरोध, दुःख-निरोध हुने आर्य अष्टाङ्गिक मार्गलाई प्रज्ञा-दृष्टिले हेरेको छ।",
  "192": "उस्ताको शरण नै रक्षादायक उत्तम शरण हो; यही शरण लिएर नै सबै तरहको दुःखबाट मुक्ति हुन्छ।",
  "193": "उत्तम पुरुष दुर्लभ छ, त्यसको सबै ठाउँमा जन्म हुँदैन । जुन कुलमा यस्ता महापुरुषको जन्म हुन्छ, त्यस कुलमा सुख-वृद्धि हुन्छ ।",
  "194": "बुद्धहरूको जन्म हुनु सुखदायक हो, सद्धर्मको उपदेश सुखदायक हो तथा एकतायुक्तहरूको तपस्या पनि सुखदायक हो ।",
  "195": "सांसारिक प्रपञ्चबाट मुक्त भइसकेका, शोक, भयरहित भइसकेका तथा निर्वाण पाइसकेका।",
  "196": "कुनै चीजमा भय नहुने पूजनीय बुद्ध अथवा श्रावकहरूलाई पूजा-सत्कार गरेको पुण्यको फल 'यति-उति' भनी कसैले पनि भन्न सक्दैन।",
  "chap15": "सुखवग्गो",
  "197": "अहो, वैरीहरूको बीचमा म शत्रु-भाव नराखेर सुखपूर्वक बसेको छु, घृणित मानिसहरूको बीचमा म घृणाको भाव नराखेर बसेको छु ।",
  "198": "आश्चर्यको कुरा छ, भयभीतको बीचमा म भयभीत नभई सुखपूर्वक बसेको छु, भयसहित मानिसको बीचमा म भयरहित भई रहेको छु ।",
  "199": "आसक्तको बीचमा, अनासक्त म सुखपूर्वक बसेको छु, आसक्तिसहित मानिसको बीचमा म अनासक्त भई बसेको छु ।",
  "200": "अहो! हामीसँग केही पनि छैन तापनि हामीहरू सुखपूर्वक बस्दछौँ, हामी आभाश्वर देवताहरू झैँ प्रीति-भोजन गरी बस्दछौँ ।",
  "201": "विजयले वैरभाव उत्पन्न गराउँदछ, पराजित पुरुष दुःखपूर्वक सुत्छ, शान्त पुरुष जय र पराजयलाई त्यागेर सुखपूर्वक सुत्छ ।",
  "202": "राग जस्तो आगो अरू छैन, द्वेष जस्तो अपराध अरू छैन, पञ्चस्कन्ध समान दुःख अरू छैन, शान्ति जस्तो सुख अरू छैन ।",
  "203": "भोक रोग हो, संस्कार परम दुःख हो । यस्तो जानेर भेट्टाएको निर्वाण नै परम सुख हो ।",
  "204": "निरोगी हुनु परम लाभ हो, सन्तोष परम धन हो, विश्वास सबभन्दा ठूलो बन्धु हो, निर्वाण परम सुख हो ।",
  "205": "एकान्तबासको रस तथा शान्तिको रसपान गर्ने सत्पुरुषलाई भय हुँदैन । धर्मको प्रेमरस पान गरेको हुनाले पाप रहित भइसकेको छ ।",
  "206": "आर्य पुरुषहरूको दर्शन गर्नु र उनीहरूको आश्रयमा बस्नु सुखकर छ, मूर्खजनहरूको दर्शन नगर्नाले सधैँ सुख हुन्छ ।",
  "207": "मूर्खहरूको सङ्गत गर्नेलाई दीर्घकालसम्म शोक हुन्छ, मूर्खसँग सङ्गत गर्नु शत्रुको सङ्गत गर्नु जस्तै दुःखद हो; धीर पण्डितहरूसँग बस्नु ज्ञाति-बन्धुहरूसँग बस्नु झैँ सुख हो ।",
  "208": "त्यसकारण तिमीहरूले पनि, चन्द्रमाले नक्षत्रपथको अनुगमन गरे झैँ धीर, प्राज्ञ, बहुश्रुत, शीलवान्, बुद्धिवान् आर्य तथा सत्पुरुषहरूको सत्सङ्गत गर!",
  "chap16": "पियवग्गो",
  "209": "खराब काममा लाग्ने, असल काममा नलाग्ने, सदर्थ छोडी प्रिय वस्तु मात्र ग्रहण गर्ने व्यक्तिले आत्माको उन्नति गर्नेमाथि स्पृहा गर्दछ ।",
  "210": "प्रेमीको र अप्रेमीको दुवैको सङ्गत नगर, प्रेमीलाई नदेख्दा र अप्रेमीलाई देख्दा दुःख हुन्छ ।",
  "211": "त्यसकारण प्रेम नगर, प्रेमीको वियोग नै दुःख हो; प्रिय र अप्रिय दुवै नहुने व्यक्तिलाई बन्धन हुने छैन ।",
  "212": "प्रियवस्तुले शोक उत्पन्न गर्दछ; प्रियवस्तुले भय उत्पन्न गराउँछ । प्रियवस्तुबाट मुक्त हुनेलाई शोक हुँदैन, भय कहाँबाट आउँछ?",
  "213": "प्रेमबाट शोक उत्पन्न हुन्छ; प्रेमबाट भय उत्पन्न हुन्छ; प्रेमबाट मुक्त हुनेलाई शोक हुँदैन, भय कहाँबाट आउँछ?",
  "214": "रागले शोक उत्पन्न गराउँछ, रागले भय उत्पन्न गराउँछ; रागबाट मुक्त हुनेलाई शोक हुँदैन, भय कहाँबाट आउँछ?",
  "215": "कामले शोक उत्पन्न गराउँछ, कामले भय उत्पन्न गराउँछ; कामबाट मुक्त हुनेलाई शोक हुँदैन, भय कताबाट आउँछ?",
  "216": "तृष्णाले शोक उत्पन्न गराउँछ, तृष्णाले भय उत्पन्न गराउँछ; तृष्णाबाट मुक्त हुनेलाई शोक हुँदैन, भय कहाँबाट आउँछ?",
  "217": "जो शील र विद्याले सम्पन्न छ, धर्ममा स्थिर छ, सत्यवादी र आफ्नो कर्ममा तत्पर छ, त्यस पुरुषलाई सबैले प्रेम गर्दछ ।",
  "218": "निर्वाणको अभिलाषा गर्ने र त्यसमा चित्त लगाउने तथा काम-विषयमा संलग्न नहुने व्यक्तिलाई उर्ध्वस्रोतगामी भन्दछन् ।",
  "219": "धेरै दिनसम्म परदेश बसेर सकुशल घर फर्कने पुरुषलाई, आफ्नो ज्ञाति-भाइ, मित्र र हितैषीहरूले स्वागत गर्दछन्।",
  "220": "त्यस्तै इहलोकबाट परलोक जाने व्यक्तिलाई आफूले गरेको पुण्यले स्वागत गर्दछ।",
  "chap17": "कोधवग्गो",
  "221": "क्रोध नगर, अभिमान नगर, सबै बन्धनबाट पार तरेर जाऊ । नाम-रूपमा आसक्त नहुने, परिग्रह-रहित व्यक्तिलाई दुःख-सन्ताप हुने छैन ।",
  "222": "जसले बढ्न गएको क्रोधलाई रथ रोके झैं रोक्छ, उसैलाई साँच्चिको सारथी भन्दछन्; अरू त केवल लगाम समात्ने मात्र हुन् ।",
  "223": "क्रोधीलाई अक्रोधले जित्नु, नराम्रो गर्नेलाई राम्रो कामले जित्नु, कृपणीलाई दानले जित्नु र असत्यवादीलाई सत्यले जित्नु ।",
  "224": "सत्य बोल्नु, क्रोध नगर्नु र माग्न आउँदा अलिकता भए पनि दिनु – यी तीन कामले मनुष्य देवलोकमा जान्छ ।",
  "225": "जो मुनीहरू सधैँ शारीरिक संयममा बसेर हिंसाले रहित हुन्छन्, त्यो अच्युत स्थानमा पुग्दछ, जहाँ पुगेर पछि शोक हुँदैन ।",
  "226": "जो सधैँ जाग्रत भएर रात-दिन योगाभ्यासमा लागिरहन्छ, निर्वाण नै जसको एकमात्र अभिलाषा हुन्छ, त्यस व्यक्तिको आस्रव र चित्तमल नष्ट हुन्छ ।",
  "227": "हे अतुल! यो पुरानो कुरा हो, अहिलेको होइन – नबोल्नेलाई पनि, धेरै बोल्नेलाई पनि, मितभाषीलाई पनि निन्दा गर्दछन् । यो लोकमा कोही पनि निन्दा-रहित हुँदैन ।",
  "228": "बिल्कुल निन्दित या बिल्कुल प्रशंसित पुरुष न उहिले थियो, न कहिल्यै होला, न आजकल हुन्छ ।",
  "229": "जुन व्यक्तिलाई पण्डितहरूले दिनपरदिन खूबै यादगारीको साथ प्रशंसा गर्दछन्, त्यस्ता दोषहीन, मेधावी, शीलवान् र प्रज्ञावान् जाम्बुनद मणि जस्तालाई कसले निन्दा गर्न सक्ला?",
  "230": "देवताले पनि, ब्रह्माले पनि उसको प्रशंसा गर्दछ।",
  "231": "शारीरिक दुराचारबाट बच, शारीरिक संयम गर, कायिक दुश्चरित्र छोडी कायिक सदाचारको आचरण गर ।",
  "232": "वाचिक दुराचारबाट बच, वाचिक संयम गर, वाचिक दुराचार छोडी वाचिक सदाचरण गर ।",
  "233": "मानसिक दुराचारबाट बच, मानसिक संयम गर, मानसिक दुराचार छोडी मानसिक सदाचरण गर ।",
  "234": "कायिक, वाचिक र मानसिक संयम हुने धीर पण्डितलाई नै सुसंयमी भन्दछन् ।",
  "chap18": "मलवग्गो",
  "235": "अहिले तिमी पहेँलो पात जस्तो छौ, यमदूतहरू तिम्रो सामु खडा छन्, विनाशको खुड्किलाका नजिक छौ, तिमीसँग बाटो-खर्च पनि छैन ।",
  "236": "त्यसकारण तिमीले आफैंलाई द्वीप (रक्षास्थान) बनाऊ, चाँडै कोशिश गरी पण्डित बन, मलरहित, कामरहित होऊ अनि दिव्य आर्यहरूको पदमा पुग्नेछौ ।",
  "237": "अब तिम्रो आयु समाप्त भयो, यमराजका अगाडि पुगिसक्यौ । बीच-बाटोमा तिम्रो निवास छैन, बाटो-खर्च पनि छैन ।",
  "238": "त्यसकारण तिमीले द्वीप बनाऊ, चाँडै कोशिश गरी पण्डित बन, मलरहित, कामरहित होऊ अनि तिमी फेरि जन्म-मरणको चक्करमा पर्नेछैनौ ।",
  "239": "सुनारले अलि-अलि गरेर चाँदीको कसर निखारे झैं, मेधावी पण्डितले अलि-अलि गरी क्रमशः आफ्नो चित्त-मल निखार्नुपर्छ ।",
  "240": "जस्तो फलामबाट निस्केको खियाले फलामलाई नै खान्छ, त्यस्तै केवल सदाचारको उल्लङ्घन गर्ने व्यक्तिलाई उसको कर्मले उसैलाई दुर्गतिमा पुऱ्याउँछ ।",
  "241": "बारबार पाठ नगर्नु मन्त्रको मैला हो, झारू-बढार नगर्नु घरको मैला हो, आलस्य सौन्दर्यको मैला हो र प्रमाद पहरेदारीको मैला हो ।",
  "242": "स्त्रीको मैला दुराचार हो, दानीको मैला कन्जुसीपन हो, इहलोक र परलोकको मैला पापै हो ।",
  "243": "त्योभन्दा पनि माथिको (खराब) मैला अविद्या हो । त्यसकारण भिक्षु हो, यो मैलालाई हटाएर निर्मल होऊ ।",
  "244": "लज्जारहित काम गर्नमा, अर्काको खोसेर खानमा वीर, अर्काको कुभलो चिताउने, बकवादी, अहंकार, भ्रष्टाचारी मनुष्यको जीवन बिताउन सजिलो छ ।",
  "245": "लाज मान्ने, सर्वदा पवित्रताको खोजी गर्ने, उद्योगी र मितभाषी भई शुद्ध जीविका गर्ने ज्ञानीको जीवन-यापन कठिन हुन्छ ।",
  "246": "हिंसक, असत्यवादी, चोरी काम गर्ने, व्यभिचारी र मद्यपान गर्ने व्यक्तिले,",
  "247": "यसै लोकमा आफ्नो उन्नतिको जड उखेल्दछ।",
  "248": "पुरुष हो! पापकर्मलाई रोक्न सजिलो छैन, लोभ र अधर्मले तिमीलाई चिरकालसम्म दुःखमा नजाकोस् ।",
  "249": "लोकललेले आफ्नो श्रद्धा र भक्तिअनुसार दान दिन्छन्; जो मानिस अर्काको खानपिन हेर्न सक्दैन, त्यसलाई दिनरात कहिले पनि शान्ति हुनेछैन, त्यसलाई ध्यान प्राप्त हुँदैन ।",
  "250": "जसले यस्तो मनोवृत्तिको जडसमेत उखेलेको छ, त्यसको मनमा दिनरात शान्ति हुन्छ र समाधि प्राप्ति हुन्छ ।",
  "251": "राग बराबरको आगो अरू छैन, द्वेष बराबरको ग्रह अरू छैन, मोह बराबरको जाल अरू छैन र तृष्णा समानको नदी अरू छैन ।",
  "252": "अर्काको दोष देख्नु सजिलो छ, किन्तु आफ्नो दोष देख्नु मुस्किल छ । अर्काको दोष भने हिम छरे झैं छरेर हिँड्छ, किन्तु आफ्नो दोष चाहिँ जाली जुवाडेले पासा छोपे झैं छोप्छ ।",
  "253": "दोषारोपण गर्ने विचारले सधैं अर्काको दोष देखिरहने व्यक्तिको चित्त-मल बढ्दछ; चित्त-मलको क्षय हुने मार्गबाट वञ्चित हुन्छ ।",
  "254": "आकाशमा केही चिन्ह नभए झैं सच्चा श्रमण बाहिर छैन; दुनियाँ प्रपञ्चमा रहेका छन्, तथागत प्रपञ्च-रहित छ ।",
  "255": "आकाशमा केही चिन्ह नभए झैं आर्य अष्टाङ्गिक मार्गको बाहिर सच्चा श्रमण छैन, संस्कृत पदार्थ नित्य छैन, बुद्धमा चञ्चलता छैन ।",
  "chap19": "धम्मट्ठवग्गो",
  "256": "बिना विचारले यदि कसैले न्याय गर्न खोज्छ भने त्यो न्यायाधीश होइन।",
  "257": "जुन पण्डितले साँचो र झूटो दुवैको निर्णय गरी, विचारपूर्वक पक्षपात नराखी न्याय गर्छ, उसैलाई धर्म रक्षा गर्ने साँचो न्यायाधीश भन्दछन्।",
  "258": "धेरै बोल्ने गर्दामा पण्डित बनिन्न; जो क्षमाशील, अवैरी तथा भयरहित छ, उसैलाई पण्डित भन्दछन् ।",
  "259": "धेरै बोल्ने गर्दामा धर्मधर कहलाइन्न; थोरै मात्र सुनेर पनि तदनुसार आचरण गर्ने नै धर्मधर कहलाइन्छ, उसको धर्ममा प्रमाद हुँदैन ।",
  "260": "केश फुल्दैमा स्थविर भनिन्न, उसको आयु परिपक्वै होस्, व्यर्थै जीवन गुमाउनेलाई 'बूढा' भनिन्छ ।",
  "261": "जसमा सत्य, धर्म, अहिंसा, संयम र दमनादि गुण छ, त्यस्तालाई निर्मल भइसकेको धीर पुरुष तथा स्थविर भन्दछन् ।",
  "262": "इर्ष्या र मात्सर्ययुक्त शठ पुरुष, वक्ता हुँदैमा अथवा रूपवान् हुँदैमा 'असल' भनिँदैन ।",
  "263": "जसले यस्तो खराब स्वभावको जड उखेली सक्यो, त्यस्ता निर्दोष, मेधावी पुरुष नै 'असल' कहलाइन्छ ।",
  "264": "मुण्डन हुँदैमा, व्रत-रहित तथा झूटो बोल्ने, इच्छा र लाभको वशमा पर्ने व्यक्ति कहिले श्रमण हुन सक्ला?",
  "265": "जसले सानो-ठूलो जुनसुकै पापलाई शमन गरिसकेको छ, त्यस्तालाई श्रमण भन्दछन् ।",
  "266": "अर्कासँग भिक्षा माग्न जाँदैमा भिक्षु हुँदैन, खराब धर्म ग्रहण गरुञ्जेलसम्म भिक्षु हुँदैन ।",
  "267": "जसले इहत्रमा पुण्य र पापलाई त्याग गरी, ब्रह्मचारी भई ज्ञानलाई लिएर लोकमा विचरण गर्दछ, त्यसलाई भिक्षु भन्दछन् ।",
  "268": "विद्याहीन मूर्ख, मौन-व्रत धारण गर्दैमा ऋषि बन्दैन।",
  "269": "जसले तराजु लिएर दुवै लोकलाई तौलेर उत्तम विचार-तत्वलाई ग्रहण गरी पाप गर्दैन, त्यस्ता पुरुष मुनि कहलाइन्छ।",
  "270": "प्राणी-हिंसा गर्नेलाई आर्य भन्दैन, सबै प्राणीको हिंसा नगर्नेलाई मात्र आर्य भन्दछन् ।",
  "271": "न शील र व्रतको आचरण मात्रले, न ठूलो पण्डित बन्नाले, न समाधि लाभ गर्नाले, न एकान्तवासी हुनाले मैले त्यो नैष्कर्म्य सुख प्राप्त गरेको हुँ, जुन सुख सारी जीवले पाउन सक्दैन।",
  "272": "भिक्षु हो, जहिले सम्म आस्रव क्षय हुँदैन त्यस बेलासम्म आफ्नो उपर विश्वास नगर।",
  "chap20": "मग्गवग्गो",
  "273": "मार्गमध्ये अष्टाङ्गिक मार्ग श्रेष्ठ, सत्यमध्ये चतुरार्य सत्य श्रेष्ठ, धर्ममध्ये वैराग्य श्रेष्ठ र मनुष्यमध्ये शुद्ध दृष्टिवाला बुद्ध श्रेष्ठ ।",
  "274": "दृष्टिको विशुद्धि गर्नका लागि अष्टाङ्गिक मार्ग छोडी अरू मार्ग छैन । भिक्षु हो, मारलाई मूर्छित गर्ने यही मार्गमा आरूढ होऊ ।",
  "275": "यही मार्गमा आरूढ भएर मात्रै दुःखको अन्त गर्न सक्छौ । शल्य समान सम्झेर मैले त्यसको उपदेश गरेको हुँ ।",
  "276": "काम त तिमीहरूले नै गर्नुपर्दछ, तथागतहरूले केवल मार्ग देखाइदिन्छन्; त्यस मार्गको आचरण गरी ध्यानाभ्यासी भएर मारको बन्धनबाट मुक्त हुन्छौ ।",
  "277": "जब सबै संस्कार अनित्य हो भनी प्रज्ञा-युक्त हुन्छ, त्यस पुरुषलाई संसारउपर वैराग्य उठ्दछ; यही विशुद्धिको मार्ग हो ।",
  "278": "सबै संस्कार दुःखका कारण हुन् भनी प्रज्ञा-युक्त भएपछि दुःखमय संसारउपर वैराग्य उठ्दछ; यही विशुद्धिको मार्ग हो ।",
  "279": "सबै धर्म (तत्व) हरू अनात्म हुन् भनी प्रज्ञा-ज्ञानले बोध भएपछि दुःखमय संसारका उपर मनमा वैराग्य उठ्दछ; यही विशुद्धिको मार्ग हो ।",
  "280": "बलवान् युवक भएर पनि अल्सी भई उद्योग गर्ने समयमा उद्योगी हुँदैन; त्यस्ताले उच्च आकांक्षाले हीन भएर प्रज्ञा-ज्ञान प्राप्त गर्न सक्दैन ।",
  "281": "वाक् र मनलाई संयम गरी शरीरले कुनै अकुशल पाप गर्दैन, यी तीन कर्म-पथलाई शुद्ध गर्ने पुरुष बुद्ध भगवान्को अष्टाङ्गिक मार्गमा जान सक्दछ ।",
  "282": "योगाभ्यास गर्नाले प्रज्ञाको वृद्धि हुन्छ । योगाभ्यास नगर्नाले प्रज्ञा-ज्ञानको क्षय हुन्छ । उन्नति र अवनतिको यी दुई प्रकारको बाटो भन्ने जानेर आफूलाई त्यस मार्गमा लगाउनु, जुन मार्गमा लाग्नाले प्रज्ञा-ज्ञानको वृद्धि हुन्छ ।",
  "283": "भिक्षु हो, वनलाई सखाप पार, तर वृक्ष नकाट । वनबाट भय हुन्छ, वन र झाडीलाई काटेर मात्रै निर्वाण प्राप्त गर्न सकिन्छ ।",
  "284": "जहिले सम्म थोरै भए पनि पुरुषको स्त्रीमाथि कामना रहन्छ, त्यसबेला सम्म दूधखाने बाछी आमाको प्रेमले आबद्ध भए झैं त्यो पुरुष बन्धनबाट मुक्त हुन सक्दैन ।",
  "285": "शरद ऋतुको कमल फूललाई झैं आफ्नो स्नेहलाई उखेल; सुगत तथागतले उपदेश गरेको शान्तिमार्ग–निर्वाणको आश्रय लेऊ ।",
  "286": "यहाँ वर्षाकालमा बस्छु, यहाँ हेमन्त ऋतुमा बस्छु भनी मूर्खजनले विचार गर्दछ । किन्तु उसलाई बीचमा विघ्न-बाधा आउने थाहा हुँदैन ।",
  "287": "निदाएको गाउँलाई बाढीले बगाए झैं पुत्र र प्राणीप्रति आसक्त भइरहने व्यक्तिलाई मृत्युले लैजान्छ ।",
  "288": "छोराले रक्षा गर्न सक्दैन, न बाबुले सक्छ, न बन्धुजनले । मृत्यु आउने बेलामा बन्धुहरूमा रक्षा गर्न सक्ने क्षमता हुँदैन ।",
  "289": "यो कुरा जानेर पण्डितले शीलवान् भएर निर्वाणतिर लैजाने मार्गलाई छिट्टै सफा गर ।",
  "chap21": "पकिण्णकवग्गो",
  "290": "थोरै सुख त्याग गरेर धेरै सुख पाइने सम्भावना भयो भने बुद्धिमानले धेरै सुखको कारण थोरै सुखलाई त्याग गर्दछ ।",
  "291": "अरूलाई दुःख दिएर आफूले सुख भोग्ने इच्छा गर्दछ भने त्यस्तो व्यक्ति द्वेषको जञ्जालमा फसेर कहिले पनि द्वेषबाट मुक्त हुन सक्दैन ।",
  "292": "गर्नुपर्ने कर्तव्य छोडेर, नगर्नुपर्ने काम गर्ने, अभिमानी तथा प्रमादीहरूको (चित्तमल) आस्रव बढ्दछ ।",
  "293": "कायानुस्मृति (अर्थात् शरीरको क्षणभङ्गुरता-दोषको स्मृति) ध्यानमा लागिरहनेले नचाहिने काम गर्दैन, चाहिने काममा मात्रै ध्यान दिइरहन्छ; यस्ता स्मृतिवान् तथा होशियार व्यक्तिको आस्रव क्षय हुन्छ ।",
  "294": "माता (तृष्णा), पिता (अहंकार), दुई क्षत्रीय राजा (शाश्वत र उच्छेद दृष्टि) र अनुचरसहित सारा राष्ट्र (विषयासक्तिहरू) लाई मारेर (ज्ञानी पुरुष) निष्पापी भएर हिँड्दछ ।",
  "295": "माता (तृष्णा), पिता (अहंकार), शाश्वत र उच्छेद दृष्टिरूपी दुई ब्राह्मण, पाँचै निवारणरूपी ब्याघ्रलाई मारेर ब्राह्मण निष्पापी भएर हिँड्दछ ।",
  "296": "रात-दिन बुद्धको गुणानुस्मरणमा लागिरहने गौतम बुद्धका शिष्यहरू सधैँ जागृत अवस्थामा हुन्छन् ।",
  "297": "रात-दिन धर्मको गुणानुस्मरणमा लागिरहने गौतम बुद्धका शिष्यहरू सधैँ जागृत भइरहन्छन् ।",
  "298": "रात-दिन संघको गुणानुस्मरणमा लागिरहने गौतम बुद्धका शिष्यहरू सधैँ जागृत भइरहन्छन् ।",
  "299": "रात-दिन कायानुस्मृतिमा लागिरहने गौतम बुद्धका शिष्यहरू सधैँ जागृत भइरहन्छन् ।",
  "300": "हरबखत अहिंसामा मन लगाइरहने गौतम बुद्धका शिष्यहरू सधैँ जागृत भइरहन्छन् ।",
  "301": "हरबखत ध्यानाभ्यासमा मन लगाइरहने गौतम बुद्धका शिष्यहरू सधैँ जागृत भइरहन्छन् ।",
  "302": "बिना नियमपूर्वक ग्रहण गरिएको प्रव्रजित जीवन बिताउनु कठिन छ । निवास गर्न अयोग्य घरमा बस्नु दुःखद छ, आफ्नो अनुकूल नभएको मानिससँग बस्नु पनि दुःखद छ; त्यसकारण संस्कृतिको बाटोमा नलाग्नु बेस, दुःखको पछि नलाग्नु बेस छ ।",
  "303": "श्रद्धावान्, शीलवान् र यशका भागी व्यक्ति जहाँ गए पनि सम्मान-सत्कारको पात्र बन्दछ ।",
  "304": "साधु-सन्तहरू टाढा बसे पनि हिमालय झैँ चम्कन्छन्, असत्पुरुषहरू रातको अन्धकारमा छोडेको बाण झैँ देखिँदैनन् ।",
  "305": "एउटै आसनमा बस्ने र एउटै शैयामा सुत्ने, आलस्यरहित तथा एक्लै विचरण गरेर आत्मदमन गर्ने पुरुष आनन्दपूर्वक जङ्गलमा बास गर्दछ ।",
  "chap22": "निरयवग्गो",
  "306": "असत्यवादी नरकमा जान्छ, 'गरेर पनि गरेको छैन' भन्ने पनि नरकमा नै जान्छ; यी दुवै प्रकारका नीच काम गर्ने मानिसहरू मृत्युपछि समान हुन्छन् ।",
  "307": "गलामा काषाय-वस्त्र धारण गर्ने कैयन असंयमी छन्, पापी छन्; तिनीहरू आफ्नो पापकर्मले गर्दा नरकमा उत्पन्न हुन्छन् ।",
  "308": "असंयमी दुराचारी भई देशको अन्न खानुभन्दा आगो झैं रातो-तातेको फलामको डल्लो खानु बेस ।",
  "309": "प्रमादी भई व्यभिचार गर्ने व्यक्तिलाई अपुण्यलाभ, सुख-निद्रा नहुनु, निन्दा र नरक-बास यति ४ गति हुन्छ।",
  "310": "अपुण्य लाभले गर्दा भविष्यमा दुर्गति प्राप्ति हुन्छ, भयभीत हुनु परेर रति-सुख अल्प हुन्छ। ठूल्ठूलो दण्ड आइपर्छ, त्यसकारण मानिसले परस्त्री-गमन नगर्नु।",
  "311": "कुश समात्दा राम्ररी नसमात्नेलाई हातमा घाउ हुन्छ । श्रमण-धर्म (सन्यास) राम्ररी पालन गरेन भने नरक जानुपर्छ ।",
  "312": "शिथिल कर्म, मलयुक्त व्रत र अशुद्ध ब्रह्मचर्य– यी कुनै पनि महाफलदायक हुँदैनन् ।",
  "313": "प्रव्रजित भएर गर्नुपर्ने काम छ भने त्यसलाई गर, झन् दृढतापूर्वक गर; शिथिल स्वभाव हुने परिब्राजकले आफ्नो मनमा चित्त-मलरूपी धूलो झनै बढाउँछ ।",
  "314": "खराब काम नगर्नु नै बेस, खराब काम गर्दा पछुतो हुन्छ । राम्रो काम गर्नु नै बेस, जुन काम गर्नाले पछि ताप हुँदैन ।",
  "315": "जस्तो सीमान्त प्रदेश भित्र र बाहिर दुवैतर्फबाट सुरक्षित हुन्छ, त्यस्तै आफ्नो सुरक्षा गर । अवसर खेर नफाल, अवसर बितेपछि नरक-बास भई अपशोच गर्नुपर्ला ।",
  "316": "लाज मान्न नहुने ठाउँमा लाज मान्दछ, लाज मान्नुपर्ने ठाउँमा लाज नमानी मिथ्या-दृष्टि ग्रहण गर्ने जीव दुर्गतिमा पुग्दछ ।",
  "317": "भय नलिनुपर्ने ठाउँमा भय लिई, भय लिनुपर्ने ठाउँमा भय नलिई मिथ्या-दृष्टि ग्रहण गर्ने जीव दुर्गतिमा पुग्दछ ।",
  "318": "निर्दोषमा दोष र दोषमा निर्दोष देखेर मिथ्या-दृष्टि ग्रहण गर्ने जीव दुर्गतिमा पुग्दछ ।",
  "319": "दोषलाई दोष र निर्दोषलाई निर्दोष नै देखेर सम्यक्-दृष्टि ग्रहण गर्ने जीवलाई स्वर्ग-प्राप्ति हुन्छ ।",
  "chap23": "नागवग्गो",
  "320": "लडाइँमा छोडेको बाण हात्तीले सहन गरे झैँ मैले अर्काको कटु वाक्य सहन गर्नेछु, किनकि संसारमा दुःशील व्यक्ति नै धेरै छन् ।",
  "321": "तालीम पाएको हात्तीलाई संग्राममा लैजान्छन्, त्यस्तो हात्तीमा राजा चढ्छन् । मनुष्यका बीचमा आत्मदमन हुने व्यक्ति श्रेष्ठ हुन्छ जसले कटु वाक्यलाई सहन गर्दछ ।",
  "322": "खच्चर, सिंधु देशको असल घोडा र महानाग हात्तीहरू दमन गर्नु उत्तम हो, तर त्योभन्दा आफ्नो दमन गर्नु झनै उत्तम ।",
  "323": "आफ्नो संयम र दमन गर्ने व्यक्ति निर्वाणतर्फ जानसक्छ; हात्ती, घोडा आदि चढी निर्वाणतर्फ जान सकिँदैन ।",
  "324": "धनपाल भन्ने हात्ती सैन्यलाई तितरबितर गर्न सक्दछ । त्यस्तो बलवान् हात्ती बन्धनमा पर्दा पनि खाने कुरो नखाई आफ्नो बस्ने मनोहर जङ्गल मात्र सम्झेर बस्दछ ।",
  "325": "धेरै आहार खाने, अल्छी, निद्रालु मानिस धेरै खानाले मोटाइराखेको सुँगुर जस्तै हो, त्यस्ता मूर्ख बराबर गर्भबासमा आउँछ ।",
  "326": "यो चित्त अघि आफ्नो इच्छा मुताविक जहाँ मन लाग्यो उहीँ जान्थ्यो । अब यसलाई मैले माहुतेले हात्तीलाई दमन गरे झैं दमन गर्नेछु ।",
  "327": "अप्रमादी हुनमा मन लगाऊ, आफ्नो चित्तको रखवारी गर, दलदल (धाप) मा परेको हात्तीले झैं आफ्नो राग, द्वेष र मोहको दलदलबाट निकाल ।",
  "328": "पाको बुद्धि भएको शीलवान् साथी पाए, सबै प्रकारका विघ्न-बाधा हट्छन् । तसर्थ सचेत तथा प्रसन्न भई त्यस व्यक्तिको सत्सङ्गत गर ।",
  "329": "पाको बुद्धि भएको तथा सच्चरित्रवान् साथी नपाए राजाले पराजित देश छोडे झैं छाडेर मातङ्ग हात्ती झैं एक्लै हिँड्नु बेस छ ।",
  "330": "मूर्खहरूको सङ्गत गर्नुभन्दा, पाप नगरी संयमी भई मातङ्ग हात्ती झैं एक्लै विचरण गर्नु बेस छ ।",
  "331": "काम पर्ने बेलामा मित्रद्वारा सहायता पाउनु सुख हो, जे मिल्यो त्यसमा सन्तुष्ट हुनु पनि सुखै हो, मृत्युपछि पुण्य पाउनु सुख हो, सबै दुःखको क्षय नै ठूलो सुख हो ।",
  "332": "संसारमा आमा-बाबुको सेवा गर्नु सुख हो, श्रमणभाव पनि सुख नै हो र पापरहित ब्राह्मणभाव झन् सुख हो ।",
  "333": "बुढेसकालसम्म शीलपालन गर्नु सुख हो, श्रद्धावान् हुनु सुख हो, प्रज्ञा-ज्ञान लाभ गर्नु सुख हो, पाप नगर्नु सुख हो ।",
  "chap24": "तण्हावग्गो",
  "334": "प्रमादी व्यक्तिको तृष्णा मालुवा लता झैं बढ्छ । फलफूलको आशा गरी जङ्गलमा उफ्रेर हिँड्ने बाँदर झैं प्रमादी व्यक्तिले संसारमा बारम्बार जन्म लिन्छ ।",
  "335": "जसलाई यो विषरूपी नीच तृष्णाले छोड्दैन, त्यसको चित्तमा वर्षामा वीरण भन्ने घाँस बढे झैं शोक बढ्दछ ।",
  "336": "किन्तु जसले यो दुष्त्याज्य नीच तृष्णालाई वशमा राख्दछ, त्यसको शोक कमलपातबाट टप्केको पानीको थोपा झैं गिर्दछ ।",
  "337": "त्यसैले यहाँ जम्मा भएका तिमीहरू सबैलाई भन्दछु– तिमीहरूको कल्याणको लागि वीरण घाँस उखेल्न खोजे झैं तिमीहरूले पनि तृष्णालाई जडैदेखि उखेल, अनि तिमीहरूलाई बाँसलाई पानीको धारले सताए झैं मारले दुःख दिन सक्दैन ।",
  "338": "जरा नउखेली केवल काटेर मात्रै राखेको रुख फेरि-फेरि उम्रे झैं, तृष्णा र अनुशयको समूल नष्ट नगर्नेलाई यो दुःख बारम्बार आउँछ ।",
  "339": "जसको छत्तीस स्रोत, संसारमा प्रिय पदार्थमा प्रवाहित भएर त्यसको रागपूर्ण संकल्पले उसलाई दुर्दृष्टितिर बगाएर लैजान्छ ।",
  "340": "यो तृष्णारूपी स्रोत जताततै बहिरहेको छ; लता फुटेर निस्केको छ । त्यो फैलिँदै आएको तृष्णारूपी लता देखेर प्रज्ञारूपी शस्त्रले त्यसको मूल समेत काट्नुपर्छ ।",
  "341": "तृष्णारूपी नदी मानिसहरूलाई खूब प्यारो तथा मनोहर लाग्दछ, सुखको कामना गर्ने मानिसहरू तृष्णा-नदीको प्रवाहमा परेर बारम्बार जन्म-मरणको फन्दामा पर्दछन् ।",
  "342": "बाँधी राखेको चौघोडा घुमिरहे झैं, तृष्णाको पीछा नछोडी संयोजन (मनको बन्धन) मा रहेका मानिसहरूलाई दीर्घकालसम्म बराबर दुःख हुन्छ ।",
  "343": "तृष्णाको पीछा गर्ने प्राणीहरू बाँधी राखेका चौघोडा झैं घुमी-घुमी रहन्छन्; अतएव भिक्षु हो, वैराग्य मार्गमा लागेर तृष्णा-निरोधको आकांक्षा गर ।",
  "344": "संसारको बन्धनबाट छुटेर वनबास गएर फेरि जङ्गल छोडी घरमै आई बस्ने मानिसलाई हेर, फेरि बन्धनैमा आइरहेको छ ।",
  "345": "फलामको, काठको र डोरीको बन्धनलाई बुद्धिमान्हरूले बलियो बन्धन भन्दैनन्। धन-सम्पत्ति, स्त्री, पुत्र, पुत्रीहरूमा हुने अनुरागलाई नै दृढ बन्धन भन्दछन्।",
  "346": "यही बन्धनलाई अधोगतिमा लैजाने शिथिल र दुष्त्याज्य बन्धन भन्दछन्, बुद्धिमान्हरू यस्तो बन्धनलाई पनि तोडी काम-सुखको इच्छा नगरी प्रव्रजित हुन्छन्।",
  "347": "रागमा लालायित व्यक्ति, आफूले बनाएको जालमा माकुरो फसे झैं आफ्नै तृष्णारूपी नदीमा पर्छ; बुद्धिमान्हरू यसलाई पनि तोडी, इच्छारहित भई सबै दुःख छोडी प्रव्रजित हुन्छन् ।",
  "348": "अगाडिको, बीचको र पछाडिको वस्तुको आशा छोडी संसारबाट पार भएर जाऊ । चारैतिरबाट आफ्नो मन मुक्त भएपछि फेरि जन्म-मरणमा आउनुपर्दैन ।",
  "349": "नाना प्रकारको सन्देह राखेर मनमा तीव्र राग राखी राम्रो-राम्रो मात्र देख्ने मानिसको तृष्णा झनै बढ्दछ । आफ्नो निम्ति उसले मजबुत बन्धन बनाउँछ ।",
  "350": "संकल्प-विकल्पलाई शान्त गर्न मन लगाई, जाग्रत भई अशुभ भावनालाई ध्यान-दृष्टिले हेर्ने व्यक्तिले जन्म-मरणबाट मुक्त भई मारको बन्धनलाई तोड्दछ ।",
  "351": "पाप-पुण्य सब त्यागिसकेर निडर भएका, तृष्णारहितलाई, चित्तमल नहुनेलाई र सांसारिक काँढा पन्छ्याई सकेकोलाई अन्तिम देहधारी भन्दछन् ।",
  "352": "तृष्णारहित, सांसारिक बन्धनबाट मुक्त, निरुक्ति-पदको विद र अक्षरहरूलाई अगाडि-पछाडि राख्नमा सिपालु, यस्ता महाप्राज्ञ अन्तिम देहधारी महापुरुष कहलाइन्छ ।",
  "353": "मैले रागादि सबैलाई जितिसकें, दुःख निवृत्तिको सबै उपाय जानिसकें, सबै पदार्थमा अलिप्त छु, सर्वत्यागी भइसकें, तृष्णा क्षय गरिसकें र विमुक्ति पाइसकेँ । मैले स्वयं विमलज्ञानको बोध पाइसकेँ, अतएव मैले कसलाई गुरु देखाऊँ?",
  "354": "सबै दानलाई धर्म-दानले जित्छ, सबै रसलाई धर्म-रसले जित्छ, सबै रतिलाई धर्म-रतिले जित्छ । तृष्णा क्षय भयो भने सबै दुःखलाई जित्छ ।",
  "355": "संसार पारी जान नखोज्ने मूर्ख भोगले नाशिन्छ, अर्कालाई नष्ट गराए झैं बराबर भोगको तृष्णामा परेर त्यस मूर्खले आफ्नो विनाश गराउँछ ।",
  "356": "खेतको दोष घाँस हो, मनुष्यको दोष राग हो । त्यसैले वीतरागलाई दिएको दानको फल ठूलो हुन्छ ।",
  "357": "खेतको दोष घाँस हो, मनुष्यको दोष द्वेष हो, त्यसैले द्वेषरहित व्यक्तिलाई दिएको दानको फल ठूलो हुन्छ ।",
  "358": "खेतको दोष घाँस हो, मनुष्यको दोष मोह हो, त्यसैले मोहरहित व्यक्तिलाई दिएको दानको फल ठूलो हुन्छ ।",
  "359": "खेतको दोष घाँस हो, मनुष्यको दोष इच्छा हो, त्यसैले इच्छारहित व्यक्तिलाई दिएको दानको फल ठूलो हुन्छ ।",
  "chap25": "भिक्खुवग्गो",
  "360": "चक्षु, श्रोत, घ्राण र जिह्वा संयम गर्नु राम्रो ।",
  "361": "काय, वाक् र मनलाई संयम राख्नु राम्रो, जहाँ पनि संयम गर्नु राम्रो, सबै कुरामा संयमको अभ्यास गर्ने भिक्षु सब तरहको दुःखबाट मुक्त हुन्छ ।",
  "362": "जसले हात, पाउ र बोली-वचनमा संयम गरेको छ, जसको चित्त अध्यात्ममा राम्ररी लागेको छ, जो समाधि-युक्त तथा सन्तुष्ट भई एकान्तमा बस्छ, उसैलाई भिक्षु भन्दछन् ।",
  "363": "जुन भिक्षुले मुखको संयम गरेर विचार गरेर कुरा गर्छ, चञ्चल स्वभाव नभई अर्थ र धर्मको प्रकाश गर्छ, यस्ताको भाषणलाई मधुर भाषण भन्दछन् ।",
  "364": "धर्ममा रमाउने, धर्ममा मन लगाउने, धर्मको चिन्तन गरी, धर्मको अनुस्मरण गरी बस्ने भिक्षु सद्धर्मबाट कहिले पनि पतन हुन पाउँदैन ।",
  "365": "आफूलाई प्राप्त हुने लाभलाई तुच्छ नसम्झनु, अर्कालाई प्राप्ति हुने लाभमा ईर्ष्या नगर्नु, अर्काको लाभमा ईर्ष्या गर्ने भिक्षुलाई समाधि प्राप्त हुन सक्दैन ।",
  "366": "थोरै भएपनि आफूलाई प्राप्त हुने लाभलाई तुच्छ नठान्नेलाई, शुद्ध जीविका गर्ने र आलस्यरहित हुने भिक्षुको प्रशंसा देवताले पनि गर्दछ ।",
  "367": "नाम-रूप जगत्मा जसले ममता राख्दैन, जसले केही नपाए पनि शोक गर्दैन, त्यस्तालाई 'भिक्षु' भन्दछ ।",
  "368": "मैत्री भावना लिएर बुद्धको उपदेशमा श्रद्धावान् भई बस्ने भिक्षुले सबै संस्कारलाई शान्त गर्ने सुखमय शान्ति-पद प्राप्त गर्दछ ।",
  "369": "भिक्षु हो! शरीररूपी डुङ्गाबाट मिथ्या-दृष्टिरूपी पानीलाई फाल्, यो पानी नभएपछि हलुङ्गो हुन्छ । राग-द्वेषलाई छिन्नभिन्न पारेर चाँडै निर्वाण प्राप्त गर ।",
  "370": "पाँचलाई काटेर, पाँचलाई छोडी, माथिल्लो पाँचको अभ्यास गर, पाँच किसिमका बन्धन पार तर्ने भिक्षुलाई 'ओघतीर्ण' भिक्षु भन्दछन् ।",
  "371": "भिक्षु हो! ध्यानमा लाग, बेहोशी नहोऊ, आफ्नो चित्तलाई कामको वशमा नपठाऊ, प्रमादी भई फलामको डल्लो नखाऊ, हाय दुःख भनेर तिमीहरूलाई पछि रुन नपरोस् ।",
  "372": "प्रज्ञा नहुनेको ध्यान हुँदैन, ध्यान नहुनेको प्रज्ञा हुँदैन, ध्यान र प्रज्ञा दुवै जसको छ उही निर्वाणको समीपमा पुग्न जान्छ ।",
  "373": "एकान्तबास गर्ने, शान्त चित्त हुने, धर्मलाई राम्ररी चिन्ने भिक्षुलाई लोकोत्तर आनन्द प्राप्ति हुन्छ ।",
  "374": "पञ्चस्कन्धको उत्पत्ति र विनाशको स्मरण गरिरहने भिक्षुलाई ज्ञानीहरूको प्रेम र अमृत-पद प्राप्ति हुन्छ ।",
  "375": "ज्ञानी भिक्षुहरूले सबभन्दा पहिले इन्द्रिय वशमा राख्नु, सन्तोष हुनु, प्रातिमोक्ष नियम पालन गर्नु । फेरि यस्ता भिक्षुले शुद्ध-जीवी र आलस्यरहित कल्याण-मित्रहरूको सत्सङ्गत गर्नुपर्छ ।",
  "376": "सेवा-सत्कार गर्ने स्वभाव भएको तथा राम्रो आचार-पालनमा निपुण भएको यस्तोले आनन्दसहित दुःखको अन्त गर्छ ।",
  "377": "भिक्षु हो! जुही फूलको बोटले ओइलाएको फूल जम्मै खसाले झैं तिमीहरूले राग-द्वेषलाई फाल्नुपर्छ ।",
  "378": "काय, वाक्, चित्त शान्त हुने र ध्यानमा सदा नियुक्त हुने, सांसारिक भोगविलासलाई त्याग गरी बस्ने भिक्षुलाई 'उपशान्त भिक्षु' भन्दछन् ।",
  "379": "आफूलाई आफैले प्रेरणा दिने, आफूलाई आफैले परीक्षा गर्ने, आत्म-संयमी र स्मृतिवान् भिक्षु सुखपूर्वक बाँच्दछ ।",
  "380": "आफ्नो स्वामी आफै हो, आफ्नो गति आफै हो, त्यसैले व्यापारीले राम्रो घोडालाई तालीममा राखे झैं आफूलाई आफैले संयममा राख्नुपर्छ ।",
  "381": "बुद्धको उपदेशमा श्रद्धा राखी सधैँ प्रमुदित हुने भिक्षुले सबै संस्कारलाई साम्य गरेर सुखमय शान्ति-पद प्राप्त गर्छ ।",
  "382": "तरुण अवस्थामा बुद्ध-शासनमा संलग्न हुने भिक्षुले बादलबाट मुक्त भई प्रकाशित हुने चन्द्रमा झैं प्रकाशित हुन्छ ।",
  "chap26": "ब्राह्मणवग्गो",
  "383": "हे ब्राह्मण, तृष्णाको स्रोतलाई काट, पराक्रम देखाएर कामवासनालाई नाश गर। हे ब्राह्मण, संस्कार सबै क्षय गरेको जानेर अकृत (निर्वाण) साक्षात्कार गर ।",
  "384": "जुन बेला ब्राह्मण चित्त-संयम र ध्यान दुई धर्ममा पारंगत हुन्छ, उसबेला त्यस ज्ञानीको सबै बन्धन नष्ट हुन्छ ।",
  "385": "जसको पार (इन्द्रिय), अपार (विषय) र पारापार (म, मेरो) भन्ने छैन, जो भयरहित भएर अनासक्त हुन्छ, उसैलाई म ब्राह्मण भन्दछु ।",
  "386": "जो ध्यानी, निर्मल, एकान्तवासी, कृतकृत्य र आस्रव-मलरहित छ, त्यसैलाई म ब्राह्मण भन्दछु ।",
  "387": "दिनमा सूर्य प्रकाशित हुन्छ, रातमा चन्द्रमा प्रकाशित हुन्छ, कवच लगाइसकेपछि क्षत्रिय प्रकाशवान् भए झैं ध्यानी भएर ब्राह्मण पनि प्रकाशवान् हुन्छ; तर बुद्ध आफ्नो तेजले रात-दिन प्रकाशवान् हुन्छ ।",
  "388": "जसले पापलाई बगाइसकेको छ उसलाई 'ब्राह्मण' र जसले राम्रो आचरण गर्ने छ उसलाई 'श्रमण' भन्दछन्; आफ्नो मल दूर गर्नेलाई 'प्रव्रजित' भन्दछन् ।",
  "389": "ब्राह्मणलाई कुट्नु हुँदैन, कुट्नेको उपर ब्राह्मणले पनि कोप गर्नु हुँदैन; ब्राह्मणलाई कुट्नेलाई धिक्कार छ, कोप गर्ने ब्राह्मणलाई पनि धिक्कार छ ।",
  "390": "मनले प्रेम गरिराखेको वस्तुबाट मनलाई हटाउनु जस्तो ठूलो कल्याण ब्राह्मणलाई अरू छैन; हिंसा-कर्मबाट मन हट्दै गयो भने दुःख शान्त भएर जान्छ ।",
  "391": "काय, वाक्, चित्त–तीनै द्वारबाट पाप नगर्ने, तीनैमा संयमी व्यक्तिलाई म ब्राह्मण भन्दछु ।",
  "392": "जसको मार्फत सम्यक्सम्बुद्धको धर्मको ज्ञान हुन्छ, उसलाई ब्राह्मणले अग्नि होत्रलाई नमस्कार गरे झैं आदरपूर्वक नमस्कार गर्नुपर्छ ।",
  "393": "जटा भएर, गोत्र भएर तथा जन्म भएर मात्रै ब्राह्मण भइन्न; जसमा सत्य र धर्म छ, उही पवित्र उही ब्राह्मण हुन्छ ।",
  "394": "हे दुर्बुद्धि, जटा पालेर मात्रै के हुन्छ? मृगचर्म लगाउँदैमा के हुन्छ? भित्र तिम्रो हृदयमा कसरले भरिएको छ भने बाहिर मात्र धोएर के हुन्छ?",
  "395": "पांंशुकूल धारण गरी, कृश भई, एकान्त जङ्गलमा बास गर्नेलाई म ब्राह्मण भन्दछु ।",
  "396": "ब्राह्मणीको कोखबाट जन्मँदैमा ब्राह्मण भन्दैन, उसलाई केवल 'भो' मात्र भन्नुपर्छ किनभने त्यसमा राग, द्वेष र मोह छ; राग-द्वेष-मोह नहुनेलाई नै म ब्राह्मण भन्दछु ।",
  "397": "सबै बन्धनलाई काटेर त्रासरहित भई, रागादि आसक्तिबाट रहित भइसकेकोलाई म ब्राह्मण भन्दछु ।",
  "398": "क्रोध, तृष्णारूपी डोरी, ६२ प्रकारको मिथ्यादृष्टिसहित अनुशयलाई तोडी, अविद्यादि क्लेशलाई निरोध गरी बोध प्राप्ति गर्नेलाई म ब्राह्मण भन्दछु ।",
  "399": "गाली र बध-बन्धनलाई जसले आफ्नो चित्त नबिगारी सहन गर्छ, राजपुरुषको सैन्यबल झैं जसको क्षान्तिबल छ, उसैलाई म ब्राह्मण भन्दछु ।",
  "400": "अक्रोधी, व्रतधारी, शीलवान्, तृष्णारहित, संयमी तथा अन्तिम देहधारीलाई नै म ब्राह्मण भन्दछु ।",
  "401": "कमल-पातमा पानीको थोपा झैं, सियोको टुप्पाको रायोको गेडा झैं, कामभोगमा लिप्त नहुने व्यक्तिलाई म ब्राह्मण भन्दछु ।",
  "402": "जसले यसै लोकमा दुःखको क्षय अनुभव गर्छ, जसले पञ्चस्कन्धरूपी भारी बिसाइकेको छ, जसको मनमा आसक्ति छैन, त्यस्ता व्यक्तिलाई म ब्राह्मण भन्दछु ।",
  "403": "गम्भीर प्रज्ञा हुने, मेधावी, कुमार्ग र सुमार्ग जान्ने, उत्तमार्थ प्राप्त गरिसकेकालाई म ब्राह्मण भन्दछु ।",
  "404": "गृहस्थ र प्रव्रजितहरू दुवैमा लिप्त नहुने, कहीँ पनि आशा तथा इच्छा नराख्नेलाई म ब्राह्मण भन्दछु ।",
  "405": "चर-अचर कुनै प्राणीमा प्रहार नगर्ने, कसैलाई नमार्ने र हिंसा गर्नमा प्रेरणा नदिने व्यक्तिलाई म ब्राह्मण भन्दछु ।",
  "406": "विरोधीहरूको बीचमा बसी विरोध नगर्ने, दण्डधारीको बीचमा बसी अदण्डधारी हुने, आसक्तहरूका बीचमा बसी अनासक्त भई बस्नेलाई म ब्राह्मण भन्दछु ।",
  "407": "जसको राग, द्वेष, मान र ईर्ष्या सियोको टुप्पाबाट सस्युँ खसे झैं खसिसक्यो, त्यसलाई म ब्राह्मण भन्दछु ।",
  "408": "जसले कसैलाई पनि पीडा दिँदैन, जसले कडा बोली बोल्दैन, जसले कारण बताई स्पष्ट रूपले सत्य प्रकाश गर्छ, त्यसलाई म ब्राह्मण भन्दछु ।",
  "409": "जसले लामो वा छोटो, पातलो वा मोटो, राम्रो वा नराम्रो– केही पनि अर्काको चोरी गरेर लिँदैन, उसलाई म ब्राह्मण भन्दछु ।",
  "410": "जसको इहलोक र परलोकमा कुनै आशा छैन, जो आशारहित, संयो गरहित व्यक्ति हो, उसैलाई म ब्राह्मण भन्दछु ।",
  "411": "आसक्ति नहुने, संशयरहित तथा सुखस्वरूप अमृत-पद प्राप्ति गरिसकेका व्यक्तिलाई म ब्राह्मण भन्दछु ।",
  "412": "पुण्य र पापबाट मुक्त भइसकेका, क्लेशरहित, शोकरहित, निर्मल व्यक्तिलाई म ब्राह्मण भन्दछु ।",
  "413": "जसले चन्द्रमा झैं निर्मल, विशुद्ध तथा स्वच्छ भई जन्म-जन्मान्तरको तृष्णालाई नष्ट पारिसकेको छ, त्यस व्यक्तिलाई म ब्राह्मण भन्दछु ।",
  "414": "जसले यो दुर्गम जन्म-मरणरूपी संसार-चक्रमा फँस्ने मोहस्वरूप उल्टो मार्गलाई त्याग गरी संसारपारी पुगिसकेको छ, जो ध्यानी, संयमी छ, जसले फेरि जन्म लिनु नपर्ने निर्वाण-पद प्राप्त गरिसकेको छ, त्यसलाई म ब्राह्मण भन्दछु ।",
  "415": "जसले कामभोग छोडी, घर छोडी प्रव्रजित भइसकेको छ, जसको काम र पुनर्जन्म नष्ट भइसकेको छ, उसलाई म ब्राह्मण भन्दछु ।",
  "416": "तृष्णालाई छोडी, घर छोडी प्रव्रजित हुने, तृष्णा र पुनर्जन्म क्षीण भइसकेकालाई म ब्राह्मण भन्दछु ।",
  "417": "मानुषिक भोग, दिव्यमय भोग र सबै प्रकारको भोग-विलास छोड्नेलाई म ब्राह्मण भन्दछु ।",
  "418": "सन्तोष र असन्तोषलाई छोडी, शान्त, क्लेशरहित भइसकेको, वीर पुरुष भई लोकलाई जित्नेलाई म ब्राह्मण भन्दछु ।",
  "419": "प्राणीहरूको उत्पत्ति र मृत्युको कारण जान्ने, आसक्तिरहित, सुगति प्राप्त, बोध भइसकेको व्यक्तिलाई म ब्राह्मण भन्दछु ।",
  "420": "जसको गति देव, गन्धर्व तथा मनुष्यहरूले जान्न सक्दैनन्, उस्ता अर्हत्लाई म ब्राह्मण भन्दछु ।",
  "421": "जसको भूत, भविष्य तथा वर्तमानबारे केही पनि इच्छा छैन, परिग्रह-रहित, 'म, मेरो' भन्ने नहुने व्यक्तिलाई म ब्राह्मण भन्दछु ।",
  "422": "निर्भीक, श्रेष्ठ, वीर, महर्षि, अपराजित, निश्चल, क्लेशरहित र चार आर्य सत्यलाई राम्रोसँग जान्ने व्यक्तिलाई म ब्राह्मण भन्दछु ।",
  "423": "पूर्व जन्म जान्ने, स्वर्ग-नरक देख्ने, पुनर्जन्म क्षीण भइसकेको, अभिज्ञा लाभ गरिसकेको, सबै काम समाप्त गरी निर्वाण प्राप्त गरिसकेको व्यक्तिलाई म ब्राह्मण भन्दछु ।"
};
